/* ─── useC()  -  get current theme colors from any component ─── */
function useC(){
  const {C}=useApp();
  return C;
}
/* ─── Module-level C fallback for non-hook contexts (Tag, Btn defaults) ─── */
let C=darkTheme;

/* ─── PERSISTENT STORAGE (localStorage) ─── */
const LS={
  get:(key,fallback=null)=>{try{const v=localStorage.getItem("plyr_"+key);return v?JSON.parse(v):fallback;}catch{return fallback;}},
  set:(key,val)=>{try{localStorage.setItem("plyr_"+key,JSON.stringify(val));}catch{}},
  del:(key)=>{try{localStorage.removeItem("plyr_"+key);}catch{}},
};

/* ── SHARED TOURNAMENT STORE ──
   All player-tournaments are stored under "plyr_tournaments" as an array.
   Any user whose username appears in league.players can see & update it.
   This simulates real-time sync within the same browser session.  */
const TStore={
  all:()=>LS.get("tournaments",[]),
  save:(tournament)=>{
    const all=TStore.all();
    const idx=all.findIndex(t=>t.id===tournament.id);
    if(idx>=0)all[idx]=tournament; else all.push(tournament);
    LS.set("tournaments",all);
    // Dispatch custom event so other "instances" (same tab) can react
    try{window.dispatchEvent(new CustomEvent("matchd_tournament_update",{detail:tournament}));}catch{}
  },
  forUser:(username)=>TStore.all().filter(t=>
    t.mode==="players"&&Array.isArray(t.players)&&
    t.players.some(p=>p.username&&p.username.toLowerCase()===username.toLowerCase())
  ),
  lookupUser:(username)=>{
    // Search all known users in localStorage for this username
    const keys=["player","referee","coach"];
    for(const k of keys){
      const u=LS.get("user_"+k,null);
      if(u&&u.username&&u.username.toLowerCase()===username.toLowerCase()) return u;
    }
    // Also check DEMO_USERS by iterating known ids
    return null;
  },
};

