function getLevel(xp=0){
  let lvl=LEVELS[0];
  for(const l of LEVELS){if(xp>=l.xpRequired)lvl=l;}
  return lvl;
}
function getLevelProgress(xp=0){
  const cur=getLevel(xp);
  const nextL=LEVELS.find(l=>l.level===cur.level+1);
  if(!nextL)return{cur,next:null,pct:100,xpToNext:0};
  const pct=Math.round(((xp-cur.xpRequired)/(nextL.xpRequired-cur.xpRequired))*100);
  return{cur,next:nextL,pct,xpToNext:nextL.xpRequired-xp};
}
