/* ─── SHARED UI ─── */
function Av({initials,size=44,color="#3B5BDB",role}){
  const C=useC();
  return(
    <div style={{position:"relative",flexShrink:0}}>
      <div style={{width:size,height:size,borderRadius:"50%",background:`linear-gradient(135deg,${color},${color}99)`,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:800,fontSize:size*0.34,border:"2px solid rgba(255,255,255,0.12)"}}>
        {initials}
      </div>
      {role==="coach"&&<div style={{position:"absolute",bottom:-2,right:-2,width:16,height:16,borderRadius:"50%",background:C.purple,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,border:"2px solid "+C.card}}>🎓</div>}
    </div>
  );
}
function Tag({text,color,small=false}){const C=useC();const _c=color||C.primary;return <span style={{background:_c+"18",color:_c,padding:small?"2px 8px":"3px 10px",borderRadius:6,fontSize:small?10:11,fontWeight:600,whiteSpace:"nowrap",border:`1px solid ${_c}28`,letterSpacing:"0.01em"}}>{text}</span>;}
function Btn({children,onClick,v="primary",full=false,sx={}}){
  const C=useC();
  const S={
    primary:{background:"linear-gradient(135deg,#00FFB3,#00CFFF)",color:"#000",fontWeight:900,border:"none",boxShadow:"0 4px 24px rgba(0,255,179,0.35)"},
    ghost:{background:"rgba(0,255,179,0.05)",color:"#00FFB3",border:"1px solid rgba(0,255,179,0.2)"},
    outline:{background:"transparent",color:"#00FFB3",border:"1px solid rgba(0,255,179,0.4)"},
    gold:{background:"linear-gradient(135deg,#FFD166,#FF9F1C)",color:"#000",fontWeight:900,border:"none"},
    purple:{background:"linear-gradient(135deg,#CC44FF,#00CFFF)",color:"#fff",fontWeight:900,border:"none"},
  };
  return <button onClick={onClick} style={{padding:"12px 18px",borderRadius:14,cursor:"pointer",fontWeight:700,fontSize:13,fontFamily:"inherit",width:full?"100%":"auto",letterSpacing:"0.04em",transition:"all 0.15s",...S[v],...sx}}>{children}</button>;
}
function Fi({label,value,onChange,ph="",type="text",multiline=false}){
  const C=useC();
  return <div style={{marginBottom:14}}>{label&&<div style={{color:C.t2,fontSize:12,marginBottom:6,direction:"rtl",fontWeight:600}}>{label}</div>}{multiline?<textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={ph} rows={3} style={{width:"100%",padding:"12px 14px",borderRadius:12,border:`1px solid ${C.inputBorder}`,background:C.inputBg,color:C.t1,fontSize:14,direction:"rtl",outline:"none",boxSizing:"border-box",fontFamily:"inherit",resize:"none"}}/>:<input value={value} onChange={e=>onChange(e.target.value)} placeholder={ph} type={type} style={{width:"100%",padding:"12px 14px",borderRadius:12,border:`1px solid ${C.inputBorder}`,background:C.inputBg,color:C.t1,fontSize:14,direction:"rtl",outline:"none",boxSizing:"border-box",fontFamily:"inherit"}}/>}</div>;
}
function Sheet({open,onClose,title,children,h="78vh"}){
  const C=useC();
  if(!open)return null;
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:9000,display:"flex",alignItems:"flex-end",backdropFilter:"blur(12px)"}} onClick={onClose}>
      <div style={{background:"rgba(8,12,30,0.92)",borderRadius:"24px 24px 0 0",width:"100%",maxWidth:430,margin:"0 auto",maxHeight:h,overflowY:"auto",border:`1px solid rgba(0,245,160,0.12)`,borderBottom:"none",boxShadow:"0 -24px 80px rgba(0,0,0,0.8)",backdropFilter:"blur(20px)",WebkitBackdropFilter:"blur(20px)"}} onClick={e=>e.stopPropagation()}>
        <div style={{padding:"14px 20px",textAlign:"center",position:"sticky",top:0,background:"rgba(8,12,30,0.95)",borderBottom:`1px solid rgba(255,255,255,0.06)`,zIndex:1,backdropFilter:"blur(20px)"}}>
          <div style={{width:36,height:4,background:"rgba(255,255,255,0.15)",borderRadius:4,margin:"0 auto 14px"}}/>
          <div style={{color:C.t1,fontWeight:700,fontSize:16,direction:"rtl",letterSpacing:"-0.01em"}}>{title}</div>
        </div>
        <div style={{padding:"20px 20px 44px"}}>{children}</div>
      </div>
    </div>
  );
}
function MSt({icon,value,label}){
  const C=useC();
  return(
    <div style={{flex:1,background:"rgba(255,255,255,0.05)",borderRadius:14,padding:"11px 8px",textAlign:"center",border:"1px solid rgba(255,255,255,0.06)"}}>
      <div style={{color:"#fff",fontWeight:800,fontSize:18,lineHeight:1,letterSpacing:"-0.02em"}}>{value}</div>
      <div style={{color:"rgba(255,255,255,0.4)",fontSize:10,marginTop:3,letterSpacing:"0.04em",textTransform:"uppercase"}}>{label}</div>
    </div>
  );
}
function EloBar({elo,sm=false}){
  const C=useC();
  const tier=getTier(elo);const next=TIERS.find(t=>t.min>elo)||tier;const pct=next.min===tier.min?100:Math.round(((elo-tier.min)/(next.min-tier.min))*100);
  if(sm)return <div style={{display:"flex",alignItems:"center",gap:5}}><span style={{fontSize:13}}>{tier.icon}</span><span style={{color:tier.color,fontWeight:700,fontSize:13}}>{elo}</span></div>;
  return(<div style={{direction:"rtl"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}><div style={{display:"flex",alignItems:"center",gap:6}}><span style={{fontSize:18}}>{tier.icon}</span><span style={{color:tier.color,fontWeight:800,fontSize:16}}>{tier.label}</span></div><span style={{color:C.t2,fontSize:13,fontWeight:700}}>ELO {elo}</span></div><div style={{height:6,background:"rgba(255,255,255,0.08)",borderRadius:4}}><div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${tier.color},${C.primary})`,borderRadius:4}}/></div><div style={{color:C.t3,fontSize:11,marginTop:4}}>{next.min-elo} נקודות לרמה הבאה</div></div>);
}

/* ─── FEED POST ─── */
function FeedPost({post}){
  const C=useC();
  const {openProfile}=useProfile();
  const [liked,setLiked]=useState(post.liked);
  const [likes,setLikes]=useState(post.likes);
  const [saved,setSaved]=useState(false);
  const [joined,setJoined]=useState(false);
  const tier=getTier(post.elo);
  return(
    <div style={{background:C.card,borderRadius:22,overflow:"hidden",border:"1px solid rgba(255,255,255,0.07)",marginBottom:14}}>
      <div style={{padding:"13px 15px 10px",display:"flex",alignItems:"center",justifyContent:"space-between",direction:"rtl"}}>
        <div onClick={()=>{const fu=OTHER_USERS.find(u=>u.initials===post.initials);if(fu)openProfile(fu);}} style={{cursor:"pointer",display:"flex",alignItems:"center",gap:10}}>
          <div style={{position:"relative"}}>
            <div style={{width:44,height:44,borderRadius:"50%",background:`linear-gradient(135deg,${post.role==="coach"?C.purple:C.blue},${post.role==="coach"?C.purple+"88":C.blue+"88"})`,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:800,fontSize:15,border:"2px solid rgba(255,255,255,0.12)"}}>{post.initials}</div>
            {post.role==="coach"&&<div style={{position:"absolute",bottom:-2,right:-2,width:16,height:16,borderRadius:"50%",background:C.purple,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,border:"2px solid "+C.card}}>🎓</div>}
          </div>
          <div>
            <div style={{display:"flex",alignItems:"center",gap:6}}><span style={{color:"#fff",fontWeight:700,fontSize:14}}>{post.user}</span>{post.role==="coach"&&<span style={{background:`${C.purple}28`,color:C.purple,padding:"1px 6px",borderRadius:10,fontSize:9,fontWeight:700}}>מאמן</span>}</div>
            <div style={{display:"flex",alignItems:"center",gap:5,marginTop:1}}><span style={{color:tier.color,fontSize:10,fontWeight:700}}>{tier.icon} {post.elo}</span><span style={{color:C.t3,fontSize:10}}>· {post.time}</span></div>
          </div>
        </div>
        <div style={{width:32,height:32,borderRadius:9,background:SG[post.sport],display:"flex",alignItems:"center",justifyContent:"center",fontSize:15}}>{SE[post.sport]}</div>
      </div>
      <div style={{padding:"0 15px 10px",direction:"rtl"}}>
        <div style={{color:"#fff",fontSize:14,lineHeight:1.6,marginBottom:10}}>{post.content}</div>
        {post.type==="result"&&post.score&&<div style={{background:`linear-gradient(135deg,${C.primary}12,${C.blue}12)`,borderRadius:16,padding:"14px",textAlign:"center",marginBottom:10,border:`1px solid ${C.primary}22`}}><div style={{color:C.t2,fontSize:11,marginBottom:4}}>📍 {post.location}</div><div style={{color:"#fff",fontWeight:900,fontSize:34,letterSpacing:5}}>{post.score}</div></div>}
        {post.isEvent&&<div style={{background:`${C.primary}10`,borderRadius:14,padding:"11px 13px",border:`1px solid ${C.primary}28`,marginBottom:10,display:"flex",alignItems:"center",justifyContent:"space-between"}}><div><div style={{color:"#fff",fontWeight:700,fontSize:13}}>📍 {post.location}</div><div style={{color:C.primary,fontSize:12,marginTop:2}}>{post.slots} מקומות פנויים</div></div><button onClick={()=>setJoined(!joined)} style={{padding:"8px 16px",borderRadius:12,border:"none",cursor:"pointer",background:joined?"rgba(255,255,255,0.08)":`linear-gradient(135deg,${C.primary},${C.blue})`,color:joined?C.t2:"#fff",fontWeight:700,fontSize:12,fontFamily:"inherit"}}>{joined?"✓ נרשמת":"הצטרף"}</button></div>}
        {!post.score&&!post.isEvent&&<div style={{color:C.t3,fontSize:12,marginBottom:8}}>📍 {post.location}</div>}
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>{post.tags.map(tag=><span key={tag} style={{background:"rgba(255,255,255,0.06)",color:C.t2,padding:"3px 9px",borderRadius:20,fontSize:11}}>{tag}</span>)}</div>
      </div>
      <div style={{padding:"9px 15px 12px",borderTop:"1px solid rgba(255,255,255,0.05)",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div style={{display:"flex",gap:18,alignItems:"center"}}>
          <button onClick={()=>{setLiked(!liked);setLikes(l=>liked?l-1:l+1);}} style={{background:"none",border:"none",cursor:"pointer",display:"flex",alignItems:"center",gap:5,color:liked?C.accent:C.t2,padding:0,fontFamily:"inherit"}}><span style={{fontSize:20}}>{liked?"❤️":"🤍"}</span><span style={{fontSize:12,fontWeight:600}}>{likes}</span></button>
          <button style={{background:"none",border:"none",cursor:"pointer",display:"flex",alignItems:"center",gap:5,color:C.t2,padding:0,fontFamily:"inherit"}}><span style={{fontSize:20}}>💬</span><span style={{fontSize:12,fontWeight:600}}>{post.comments}</span></button>
          <button style={{background:"none",border:"none",cursor:"pointer",color:C.t2,padding:0,fontSize:20}}>↗️</button>
        </div>
        <button onClick={()=>setSaved(!saved)} style={{background:"none",border:"none",cursor:"pointer",color:saved?C.gold:C.t2,padding:0,fontSize:20}}>{saved?"🔖":"🏷️"}</button>
      </div>
    </div>
  );
}

