/* ─── HOME PAGE - TikTok style ─── */
/* ═══════════════════════════════════════════════════════
   ANALYTICS ENGINE
   ═══════════════════════════════════════════════════════ */
const Analytics={
  _q:[],
  track(event,props={}){
    const entry={event,props,ts:Date.now()};
    this._q.push(entry);
    // In production: send to backend. Here we log + store locally.
    try{
      const existing=JSON.parse(localStorage.getItem("plyr_analytics")||"[]");
      existing.push(entry);
      // keep last 200 events
      if(existing.length>200) existing.splice(0,existing.length-200);
      localStorage.setItem("plyr_analytics",JSON.stringify(existing));
    }catch(e){}
    if(typeof window!=="undefined"&&window._plyrDebug){
      console.log(`[PLYR Analytics] ${event}`,props);
    }
  },
  getAll(){
    try{return JSON.parse(localStorage.getItem("plyr_analytics")||"[]");}catch(e){return[];}
  },
  // Standard event helpers
  signupStarted:()=>Analytics.track("signup_started"),
  signupCompleted:(role)=>Analytics.track("signup_completed",{role}),
  firstMatchViewed:(matchId)=>Analytics.track("first_match_viewed",{matchId}),
  firstJoinClicked:(matchId)=>Analytics.track("first_join_clicked",{matchId}),
  firstGameConfirmed:(matchId)=>Analytics.track("first_game_confirmed",{matchId}),
  gameCompleted:(gameId)=>Analytics.track("game_completed",{gameId}),
  ratedAfterGame:(gameId,rating)=>Analytics.track("rated_after_game",{gameId,rating}),
  invitedFriend:(channel)=>Analytics.track("invited_friend",{channel}),
  friendJoined:(friendId)=>Analytics.track("friend_joined",{friendId}),
  userReturnedDay7:()=>Analytics.track("user_returned_day_7"),
  availableNowSet:(slot)=>Analytics.track("available_now_set",{slot}),
  shareGameClicked:(gameId,channel)=>Analytics.track("share_game_clicked",{gameId,channel}),
  reportSubmitted:(type)=>Analytics.track("report_submitted",{type}),
};

/* ═══════════════════════════════════════════════════════
   TRUST & SAFETY + REPUTATION SYSTEM
   ═══════════════════════════════════════════════════════ */

// Reliability Score = composite: show_rate + cancel_rate + avg_rating + repeat_games + responsiveness
function calcReliabilityScore(user){
  const base = user?.reliabilityScore || 87;
  return base;
}

function ReliabilityBadge({score, size="normal"}){
  const C=useC();
  const color = score>=90?"#00FFB3":score>=75?"#FFD166":score>=60?"#FF9A3C":"#FF4757";
  const label = score>=90?"אמין מאוד":score>=75?"אמין":score>=60?"בינוני":"לא אמין";
  const small = size==="small";
  return(
    <div style={{display:"inline-flex",alignItems:"center",gap:small?4:6,
      background:`${color}12`,border:`1px solid ${color}30`,borderRadius:small?8:12,
      padding:small?"3px 8px":"6px 12px"}}>
      <div style={{width:small?6:8,height:small?6:8,borderRadius:"50%",background:color,
        boxShadow:`0 0 ${small?4:6}px ${color}`}}/>
      <span style={{color,fontWeight:700,fontSize:small?9:11}}>{score}%</span>
      {!small&&<span style={{color:`${color}88`,fontSize:9}}>{label}</span>}
    </div>
  );
}

function TrustBadges({user}){
  const C=useC();
  const badges=[
    {key:"verified_phone",icon:"📱",label:"טלפון מאומת",color:"#00FFB3",active:user?.verifiedPhone??true},
    {key:"id_verified",icon:"🪪",label:"זהות מאומתת",color:"#4D9FFF",active:user?.idVerified??false},
    {key:"reliable",icon:"⭐",label:"שחקן אמין",color:"#FFD166",active:calcReliabilityScore(user)>=80},
    {key:"no_noshow",icon:"✅",label:"אף פעם לא נעדר",color:"#00C07F",active:user?.noShows===0},
  ];
  return(
    <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
      {badges.filter(b=>b.active).map(b=>(
        <div key={b.key} style={{display:"inline-flex",alignItems:"center",gap:4,
          background:`${b.color}10`,border:`1px solid ${b.color}25`,borderRadius:10,padding:"3px 8px"}}>
          <span style={{fontSize:11}}>{b.icon}</span>
          <span style={{color:b.color,fontSize:9,fontWeight:700}}>{b.label}</span>
        </div>
      ))}
    </div>
  );
}

function ReportSheet({onClose, targetName="משתמש"}){
  const C=useC();
  const [step,setStep]=useState("type"); // type | details | done
  const [type,setType]=useState(null);
  const [details,setDetails]=useState("");

  const TYPES=[
    {k:"noshow",icon:"👻",label:"לא הגיע למשחק",color:"#FF9A3C"},
    {k:"harassment",icon:"🚫",label:"הטרדה / אלימות",color:"#FF4757"},
    {k:"fake",icon:"🤥",label:"פרופיל מזויף",color:"#CC44FF"},
    {k:"cheating",icon:"🎭",label:"רמאות / חוסר ספורטיביות",color:"#FFD166"},
    {k:"other",icon:"⚠️",label:"אחר",color:"rgba(255,255,255,0.4)"},
  ];

  if(step==="done") return(
    <div style={{padding:"32px 20px",textAlign:"center",direction:"rtl"}}>
      <div style={{fontSize:52,marginBottom:12}}>✅</div>
      <div style={{color:"#fff",fontWeight:800,fontSize:18,marginBottom:8}}>הדיווח נשלח</div>
      <div style={{color:"rgba(255,255,255,0.5)",fontSize:13,marginBottom:24,lineHeight:1.6}}>
        הצוות שלנו יבדוק את הדיווח תוך 24 שעות.<br/>אנחנו שומרים על קהילה בטוחה.
      </div>
      <button onClick={onClose} style={{padding:"13px 32px",borderRadius:14,border:"none",
        background:"#00C07F",color:"#000",fontWeight:800,fontSize:14,cursor:"pointer",fontFamily:"inherit"}}>
        סגור
      </button>
    </div>
  );

  return(
    <div style={{direction:"rtl",padding:"4px 0 20px"}}>
      {step==="type"&&(<>
        <div style={{color:"rgba(255,255,255,0.5)",fontSize:12,marginBottom:14,lineHeight:1.6,padding:"0 4px"}}>
          דיווח על <strong style={{color:"#fff"}}>{targetName}</strong> יועבר לצוות הבטיחות שלנו לבדיקה.
        </div>
        {TYPES.map(t=>(
          <button key={t.k} onClick={()=>{setType(t.k);setStep("details");}}
            style={{width:"100%",padding:"14px 16px",borderRadius:14,border:`1px solid ${t.color}25`,
              background:`${t.color}08`,marginBottom:8,cursor:"pointer",fontFamily:"inherit",
              display:"flex",alignItems:"center",gap:12,direction:"rtl"}}>
            <span style={{fontSize:20}}>{t.icon}</span>
            <span style={{color:"#fff",fontWeight:600,fontSize:14}}>{t.label}</span>
            <span style={{marginRight:"auto",color:"rgba(255,255,255,0.3)",fontSize:18}}>←</span>
          </button>
        ))}
      </>)}
      {step==="details"&&(<>
        <div style={{color:"#fff",fontWeight:700,fontSize:15,marginBottom:12}}>
          {TYPES.find(t=>t.k===type)?.icon} {TYPES.find(t=>t.k===type)?.label}
        </div>
        <textarea value={details} onChange={e=>setDetails(e.target.value)}
          placeholder="תאר את האירוע (אופציונלי)..."
          style={{width:"100%",padding:"14px",borderRadius:14,border:"1px solid rgba(255,255,255,0.1)",
            background:"rgba(255,255,255,0.04)",color:"#fff",fontSize:13,resize:"none",height:100,
            fontFamily:"inherit",boxSizing:"border-box",marginBottom:14}}/>
        <button onClick={()=>{Analytics.reportSubmitted(type);setStep("done");}}
          style={{width:"100%",padding:"14px",borderRadius:14,border:"none",
            background:"linear-gradient(135deg,#FF4757,#CC0020)",color:"#fff",fontWeight:800,
            fontSize:15,cursor:"pointer",fontFamily:"inherit",marginBottom:10}}>
          שלח דיווח
        </button>
        <button onClick={()=>setStep("type")}
          style={{width:"100%",padding:"12px",borderRadius:14,border:"none",background:"transparent",
            color:"rgba(255,255,255,0.4)",fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>
          חזרה
        </button>
      </>)}
    </div>
  );
}

