/* ═══════════════════════════════════════════════════════
   AI MATCH SCORE
   ═══════════════════════════════════════════════════════ */
function AIMatchScore({score=92, reasons=[]}){
  const C=useC();
  const color=score>=85?"#00FFB3":score>=70?"#FFD166":"#FF4757";
  const defaultReasons=[
    {icon:"🎯",text:"רמה דומה (ELO ±50)"},
    {icon:"📍",text:"מרחק 1.2 ק\"מ"},
    {icon:"👥",text:"חבר משותף אחד"},
    {icon:"🕐",text:"זמן מתאים להיסטוריה"},
  ];
  const displayReasons=reasons.length?reasons:defaultReasons;
  return(
    <div style={{background:"rgba(0,255,179,0.04)",border:"1px solid rgba(0,255,179,0.18)",
      borderRadius:14,padding:"10px 14px",marginBottom:10}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
        <div style={{width:40,height:40,borderRadius:"50%",
          background:`conic-gradient(${color} ${score*3.6}deg, rgba(255,255,255,0.06) 0deg)`,
          display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
          <div style={{width:32,height:32,borderRadius:"50%",background:"#010608",
            display:"flex",alignItems:"center",justifyContent:"center"}}>
            <span style={{color,fontWeight:900,fontSize:12}}>{score}</span>
          </div>
        </div>
        <div>
          <div style={{color:color,fontWeight:800,fontSize:13}}>🤖 Match Score: {score}%</div>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:10,marginTop:1}}>התאמה גבוהה לפרופיל שלך</div>
        </div>
      </div>
      <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
        {displayReasons.map((r,i)=>(
          <div key={i} style={{display:"inline-flex",alignItems:"center",gap:4,
            background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.07)",
            borderRadius:8,padding:"3px 8px"}}>
            <span style={{fontSize:10}}>{r.icon}</span>
            <span style={{color:"rgba(255,255,255,0.5)",fontSize:9}}>{r.text}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

