const CHEMISTRY_DATA = [
  {player:"adi_soccer",initials:"AD",color:"#3B5BDB",chemistry:94,gamesTogther:8,wins:6,style:"התקפי",note:"משלימים מצוין — אתה הגנתי, הוא התקפי"},
  {player:"ron_bball",initials:"RB",color:"#F08C00",chemistry:87,gamesTogther:5,wins:4,style:"קבוצתי",note:"קצב משחק דומה, תקשורת מעולה"},
  {player:"maya_run",initials:"MY",color:"#E03131",chemistry:71,gamesTogther:3,wins:2,style:"מהיר",note:"פוטנציאל גבוה, עוד צריכים להיכנס לקצב"},
  {player:"dan_bball",initials:"DB",color:"#2F9E44",chemistry:65,gamesTogther:2,wins:1,style:"טכני",note:"סגנונות שונים — דורש הסתגלות"},
];

function ChemistryTab(){
  const C = useC();
  return(
    <div style={{direction:"rtl"}}>
      <div style={{background:"linear-gradient(135deg,rgba(204,68,255,0.08),rgba(77,159,255,0.04))",
        border:"1px solid rgba(204,68,255,0.2)",borderRadius:16,padding:"12px 14px",marginBottom:14,
        display:"flex",gap:10,alignItems:"center"}}>
        <span style={{fontSize:22}}>🔗</span>
        <div>
          <div style={{color:"#CC44FF",fontWeight:700,fontSize:13}}>Chemistry — כימיה בין שחקנים</div>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginTop:2}}>
            כמה אתה ואחרים משלימים אחד את השני
          </div>
        </div>
      </div>
      {CHEMISTRY_DATA.map(p=>{
        const chemColor = p.chemistry>=85?"#00FFB3":p.chemistry>=70?"#FFD166":"#FF9A3C";
        return(
          <div key={p.player} style={{background:"rgba(255,255,255,0.02)",borderRadius:15,padding:"13px 14px",
            marginBottom:9,border:"1px solid rgba(255,255,255,0.06)"}}>
            <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
              <div style={{width:40,height:40,borderRadius:"50%",
                background:`linear-gradient(135deg,${p.color},${p.color}99)`,
                display:"flex",alignItems:"center",justifyContent:"center",
                color:"#fff",fontWeight:800,fontSize:14,flexShrink:0}}>
                {p.initials}
              </div>
              <div style={{flex:1}}>
                <div style={{color:"#fff",fontWeight:700,fontSize:13,marginBottom:2}}>{p.player}</div>
                <div style={{color:"rgba(255,255,255,0.35)",fontSize:10}}>
                  🏟️ {p.gamesTogther} משחקים יחד · {p.wins} ניצחונות
                </div>
              </div>
              {/* Chemistry ring */}
              <div style={{position:"relative",width:50,height:50}}>
                <svg width="50" height="50" style={{transform:"rotate(-90deg)"}}>
                  <circle cx="25" cy="25" r="20" fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="4"/>
                  <circle cx="25" cy="25" r="20" fill="none" stroke={chemColor} strokeWidth="4"
                    strokeDasharray={`${p.chemistry*1.257} 125.7`} strokeLinecap="round"/>
                </svg>
                <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",
                  justifyContent:"center",flexDirection:"column"}}>
                  <span style={{color:chemColor,fontWeight:900,fontSize:12,lineHeight:1}}>{p.chemistry}</span>
                  <span style={{color:"rgba(255,255,255,0.35)",fontSize:7}}>%</span>
                </div>
              </div>
            </div>
            {/* Note */}
            <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,padding:"7px 10px",
              background:"rgba(255,255,255,0.03)",borderRadius:9,lineHeight:1.5}}>
              💡 {p.note}
            </div>
            {/* Actions */}
            <div style={{display:"flex",gap:8,marginTop:8}}>
              <button style={{flex:1,padding:"7px",borderRadius:9,border:`1px solid ${chemColor}30`,
                background:`${chemColor}08`,color:chemColor,fontSize:10,fontWeight:700,
                cursor:"pointer",fontFamily:"inherit"}}>
                ⚽ שחק איתו שוב
              </button>
              <button style={{padding:"7px 10px",borderRadius:9,border:"1px solid rgba(255,255,255,0.1)",
                background:"transparent",color:"rgba(255,255,255,0.4)",fontSize:10,cursor:"pointer",fontFamily:"inherit"}}>
                💬
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

