    badge:"rgba(204,68,255,0.12)",badgeBorder:"rgba(204,68,255,0.28)",
    cardBg:"rgba(204,68,255,0.04)",cardBorder:"rgba(204,68,255,0.12)",
    neon:"0 0 20px rgba(204,68,255,0.35),0 0 40px rgba(204,68,255,0.12)",
