/* ─── REFEREE GAME DETAIL MODAL ─── */
function RefGameDetailModal({game, onClose}){
  const C=useC();
  if(!game)return null;
  const statusColor=game.status==="מאושר"?"#00FFB3":game.status==="ממתין לאישור"?"#FFD166":"#FF3D71";
  return(
    <div style={{position:"fixed",inset:0,zIndex:9500,background:"rgba(0,0,0,0.85)",backdropFilter:"blur(12px)",display:"flex",alignItems:"flex-end"}} onClick={onClose}>
      <div style={{width:"100%",maxWidth:430,margin:"0 auto",background:"rgba(5,10,25,0.97)",borderRadius:"24px 24px 0 0",padding:"20px 20px 48px",border:"1px solid rgba(255,209,102,0.25)",boxShadow:"0 -20px 80px rgba(255,209,102,0.15)",direction:"rtl"}} onClick={e=>e.stopPropagation()}>
        {/* Handle */}
        <div style={{width:36,height:4,borderRadius:2,background:"rgba(255,209,102,0.3)",margin:"0 auto 18px"}}/>
        {/* Header */}
        <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:18}}>
          <div style={{width:50,height:50,borderRadius:14,background:`${game.color}18`,border:`1.5px solid ${game.color}40`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,flexShrink:0}}>
            {game.sport==="כדורגל"?"⚽":game.sport==="כדורסל"?"🏀":game.sport==="טניס"?"🎾":"🏅"}
          </div>
          <div style={{flex:1}}>
            <div style={{color:"#FFFDE8",fontWeight:900,fontSize:17,lineHeight:1.2}}>{game.name}</div>
            <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginTop:3}}>{game.sport} · {game.type}</div>
          </div>
          <div style={{background:`${statusColor}18`,border:`1px solid ${statusColor}33`,borderRadius:10,padding:"4px 10px"}}>
            <span style={{color:statusColor,fontSize:11,fontWeight:800}}>{game.status}</span>
          </div>
        </div>
        {/* Detail rows */}
        {[
          {icon:"💰",label:"שכר שיפוט",val:`₪${game.pay}`,color:"#FFD166"},
          {icon:"⏱️",label:"שעות",val:`${game.time} – ${game.end}`,color:"#4D9FFF"},
          {icon:"📍",label:"מיקום",val:game.location,color:"#00FFB3"},
          {icon:"📅",label:"ספורט",val:game.sport,color:"#CC44FF"},
          {icon:"👤",label:"מארגן",val:game.organizer,color:"rgba(255,255,255,0.7)"},
          {icon:"ℹ️",label:"פרטים",val:game.details,color:"rgba(255,255,255,0.5)"},
        ].map(row=>(
          <div key={row.label} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 0",borderBottom:"1px solid rgba(255,255,255,0.05)"}}>
            <div style={{width:36,height:36,borderRadius:10,background:"rgba(255,255,255,0.05)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>{row.icon}</div>
            <div style={{flex:1}}>
              <div style={{color:"rgba(255,255,255,0.35)",fontSize:10,marginBottom:2}}>{row.label}</div>
              <div style={{color:row.color,fontWeight:700,fontSize:14}}>{row.val}</div>
            </div>
          </div>
        ))}
        {/* Participants */}
        {game.participants&&game.participants.length>0&&(
          <div style={{padding:"11px 0",borderBottom:"1px solid rgba(255,255,255,0.05)"}}>
            <div style={{display:"flex",alignItems:"center",gap:12}}>
              <div style={{width:36,height:36,borderRadius:10,background:"rgba(255,255,255,0.05)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>👥</div>
              <div style={{flex:1}}>
                <div style={{color:"rgba(255,255,255,0.35)",fontSize:10,marginBottom:4}}>קבוצות / שחקנים</div>
                <div style={{display:"flex",gap:7,flexWrap:"wrap"}}>
                  {game.participants.map((p,i)=>(
                    <div key={i} style={{background:"rgba(255,209,102,0.08)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:8,padding:"3px 10px",color:"#FFD166",fontSize:12,fontWeight:600}}>{p}</div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
        {/* Action buttons */}
        <div style={{display:"flex",gap:10,marginTop:20}}>
          <button onClick={onClose} style={{flex:1,padding:"13px",borderRadius:14,border:"1px solid rgba(255,255,255,0.12)",background:"transparent",color:"rgba(255,255,255,0.4)",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>סגור</button>
          {game.status==="ממתין לאישור"&&(
            <button onClick={onClose} style={{flex:2,padding:"13px",borderRadius:14,border:"none",background:"linear-gradient(135deg,#FFD166,#FF9A3C)",color:"#000",fontWeight:900,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>✓ אשר שיפוט</button>
          )}
          {game.status==="מאושר"&&(
            <button onClick={onClose} style={{flex:2,padding:"13px",borderRadius:14,border:"none",background:"linear-gradient(135deg,#FFD166,#4D9FFF)",color:"#000",fontWeight:900,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>📋 פרטים מלאים</button>
          )}
        </div>
      </div>
    </div>
  );
}

function RefereeScheduleTab({RC,mounted}){
  const C=useC();
  const [view,setView]=useState("week");
  const [selectedDate,setSelectedDate]=useState("2026-03-10");
  const [scheduleData,setScheduleData]=useState(REF_SCHEDULE_DATA);
  const [bookingOpen,setBookingOpen]=useState(false);
  const [selectedGame,setSelectedGame]=useState(null);
  const today="2026-03-10";
  const selDateObj=new Date(selectedDate+"T12:00:00");
  const getWeekDates=(dateStr)=>{const d=new Date(dateStr+"T12:00:00");const day=d.getDay();const sun=new Date(d);sun.setDate(d.getDate()-day);return Array.from({length:7},(_,i)=>{const dd=new Date(sun);dd.setDate(sun.getDate()+i);return dd.toISOString().slice(0,10);});};
  const getMonthDates=(dateStr)=>{const d=new Date(dateStr+"T12:00:00");const first=new Date(d.getFullYear(),d.getMonth(),1);const last=new Date(d.getFullYear(),d.getMonth()+1,0);const dates=[];for(let i=0;i<first.getDay();i++)dates.push(null);for(let i=1;i<=last.getDate();i++)dates.push(new Date(d.getFullYear(),d.getMonth(),i).toISOString().slice(0,10));return dates;};
  const weekDates=getWeekDates(selectedDate);
  const monthDates=getMonthDates(selectedDate);
  const daySessions=scheduleData[selectedDate]||[];
  const navWeek=(dir)=>{const d=new Date(selectedDate+"T12:00:00");d.setDate(d.getDate()+dir*7);setSelectedDate(d.toISOString().slice(0,10));};
  const navMonth=(dir)=>{const d=new Date(selectedDate+"T12:00:00");d.setMonth(d.getMonth()+dir);setSelectedDate(d.toISOString().slice(0,10));};
  const countGames=(dates)=>dates.reduce((s,d)=>s+(scheduleData[d]||[]).length,0);
  const viewGames=view==="day"?daySessions.length:view==="week"?countGames(weekDates):countGames(getMonthDates(selectedDate).filter(Boolean));
  const ratePerGame=parseInt(RC?.primary?"200":"200")||200;

  return(
    <div style={{direction:"rtl"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
        <div style={{color:"#FFFDE8",fontWeight:800,fontSize:14}}>📅 לוח משחקים</div>
        <button onClick={()=>setBookingOpen(true)}
          style={{padding:"6px 13px",borderRadius:20,border:"1px solid rgba(255,209,102,0.3)",
            background:"rgba(255,209,102,0.1)",color:"#FFD166",fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>
          + קביעה
        </button>
      </div>
      {/* View switcher */}
      <div style={{display:"flex",background:"rgba(255,255,255,0.04)",borderRadius:11,padding:3,marginBottom:10,border:"1px solid rgba(255,209,102,0.1)"}}>
        {[["day","יומי"],["week","שבועי"],["month","חודשי"]].map(([k,l])=>(
          <button key={k} onClick={()=>setView(k)}
            style={{flex:1,padding:"7px",borderRadius:9,border:"none",cursor:"pointer",fontFamily:"inherit",
              fontWeight:700,fontSize:12,background:view===k?"#FFD166":"transparent",
              color:view===k?"#000":"rgba(255,255,255,0.4)"}}>
            {l}
          </button>
        ))}
      </div>
      {/* Stats badge */}
      <div style={{background:"rgba(255,209,102,0.07)",border:"1px solid rgba(255,209,102,0.18)",borderRadius:10,padding:"7px 12px",marginBottom:12,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{color:"rgba(255,255,255,0.4)",fontSize:11}}>{view==="day"?"משחקים היום":view==="week"?"משחקים השבוע":"משחקים החודש"}</span>
        <span style={{color:"#FFD166",fontWeight:800,fontSize:14}}>{viewGames} משחקים · ₪{(viewGames*200).toLocaleString()}</span>
      </div>
      {/* DAY */}
      {view==="day"&&(
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
            <button onClick={()=>{const d=new Date(selectedDate+"T12:00:00");d.setDate(d.getDate()-1);setSelectedDate(d.toISOString().slice(0,10));}}
              style={{background:"rgba(255,209,102,0.1)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:9,width:32,height:32,cursor:"pointer",color:"#FFD166",fontSize:16,fontFamily:"inherit"}}>‹</button>
            <div style={{textAlign:"center"}}>
              <div style={{color:"#FFFDE8",fontWeight:800,fontSize:15}}>{HE_DAYS[selDateObj.getDay()]}</div>
              <div style={{color:C.t3,fontSize:11}}>{selDateObj.getDate()} {HE_MONTHS[selDateObj.getMonth()]}</div>
            </div>
            <button onClick={()=>{const d=new Date(selectedDate+"T12:00:00");d.setDate(d.getDate()+1);setSelectedDate(d.toISOString().slice(0,10));}}
              style={{background:"rgba(255,209,102,0.1)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:9,width:32,height:32,cursor:"pointer",color:"#FFD166",fontSize:16,fontFamily:"inherit"}}>›</button>
          </div>
          {daySessions.length===0
            ?<div style={{textAlign:"center",padding:"32px 0",color:"rgba(255,255,255,0.2)",fontSize:13}}>אין משחקים היום</div>
            :daySessions.map((s,i)=>(
              <div key={i} onClick={()=>setSelectedGame(s)} style={{background:`${s.color}10`,border:`1px solid ${s.color}30`,borderRadius:13,padding:"12px 14px",marginBottom:9,
                display:"flex",alignItems:"center",gap:12,animation:mounted?`fadeInUp 0.3s ease ${i*60}ms both`:"none",cursor:"pointer",transition:"all 0.15s"}}>
                <div style={{background:`${s.color}20`,borderRadius:9,padding:"8px 10px",textAlign:"center",minWidth:52}}>
                  <div style={{color:s.color,fontWeight:800,fontSize:12}}>{s.time}</div>
                  <div style={{color:"rgba(255,255,255,0.3)",fontSize:9}}>{s.end}</div>
                </div>
                <div style={{flex:1}}>
                  <div style={{color:"#FFFDE8",fontWeight:700,fontSize:13}}>{s.name}</div>
                  <div style={{color:s.color,fontSize:10,fontWeight:600,marginTop:2}}>⚖️ {s.type} {s.location?`· 📍${s.location}`:""}</div>
                </div>
                <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:4}}>
                  <div style={{background:`${s.color}15`,borderRadius:8,padding:"3px 9px"}}>
                    <span style={{color:s.color,fontSize:10,fontWeight:700}}>₪{s.pay||200}</span>
                  </div>
                  <span style={{color:"rgba(255,255,255,0.3)",fontSize:9}}>›</span>
                </div>
              </div>
            ))
          }
        </div>
      )}
      {/* WEEK */}
      {view==="week"&&(
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
            <button onClick={()=>navWeek(-1)} style={{background:"rgba(255,209,102,0.1)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:9,width:32,height:32,cursor:"pointer",color:"#FFD166",fontSize:16,fontFamily:"inherit"}}>‹</button>
            <div style={{color:C.t3,fontSize:11,textAlign:"center"}}>
              {new Date(weekDates[0]+"T12:00:00").getDate()} — {new Date(weekDates[6]+"T12:00:00").getDate()} {HE_MONTHS[new Date(weekDates[0]+"T12:00:00").getMonth()]}
            </div>
            <button onClick={()=>navWeek(1)} style={{background:"rgba(255,209,102,0.1)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:9,width:32,height:32,cursor:"pointer",color:"#FFD166",fontSize:16,fontFamily:"inherit"}}>›</button>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:4,marginBottom:12}}>
            {weekDates.map((d,i)=>{
              const ss=scheduleData[d]||[];
              const isSel=d===selectedDate;
              return(
                <button key={d} onClick={()=>{setSelectedDate(d);setView("day");}}
                  style={{padding:"7px 3px",borderRadius:10,border:`1px solid ${isSel?"#FFD166":ss.length?"rgba(255,209,102,0.25)":"rgba(255,255,255,0.06)"}`,
                    background:isSel?"rgba(255,209,102,0.15)":ss.length?"rgba(255,209,102,0.04)":"transparent",
                    cursor:"pointer",fontFamily:"inherit",textAlign:"center"}}>
                  <div style={{color:isSel?"#FFD166":C.t3,fontSize:9,fontWeight:700}}>{HE_DAYS_SHORT[i]}</div>
                  <div style={{color:isSel?"#FFFDE8":C.t2,fontWeight:800,fontSize:13,margin:"2px 0"}}>{new Date(d+"T12:00:00").getDate()}</div>
                  <div style={{display:"flex",justifyContent:"center",gap:2}}>
                    {ss.slice(0,3).map((_,j)=><div key={j} style={{width:4,height:4,borderRadius:"50%",background:ss[j]?.color||"#FFD166"}}/>)}
                  </div>
                </button>
              );
            })}
          </div>
          {weekDates.map(d=>{
            const ss=scheduleData[d]||[];
            if(!ss.length) return null;
            const dObj=new Date(d+"T12:00:00");
            return(
              <div key={d} style={{marginBottom:10}}>
                <div style={{color:C.t3,fontSize:10,fontWeight:700,marginBottom:5}}>{HE_DAYS[dObj.getDay()]} {dObj.getDate()}/{dObj.getMonth()+1}</div>
                {ss.map((s,i)=>(
                  <div key={i} onClick={()=>setSelectedGame(s)} style={{background:`${s.color}08`,border:`1px solid ${s.color}22`,borderRadius:10,padding:"8px 11px",marginBottom:5,display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
                    <span style={{color:s.color,fontWeight:800,fontSize:11,minWidth:36}}>{s.time}</span>
                    <span style={{color:"#FFFDE8",fontSize:12,flex:1}}>{s.name}</span>
                    <span style={{background:`${s.color}15`,color:s.color,fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:6}}>{s.type}</span>
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      )}
      {/* MONTH */}
      {view==="month"&&(
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
            <button onClick={()=>navMonth(-1)} style={{background:"rgba(255,209,102,0.1)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:9,width:32,height:32,cursor:"pointer",color:"#FFD166",fontSize:16,fontFamily:"inherit"}}>‹</button>
            <div style={{color:"#FFFDE8",fontWeight:700,fontSize:13}}>{HE_MONTHS[selDateObj.getMonth()]} {selDateObj.getFullYear()}</div>
            <button onClick={()=>navMonth(1)} style={{background:"rgba(255,209,102,0.1)",border:"1px solid rgba(255,209,102,0.2)",borderRadius:9,width:32,height:32,cursor:"pointer",color:"#FFD166",fontSize:16,fontFamily:"inherit"}}>›</button>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3,marginBottom:8}}>
            {HE_DAYS_SHORT.map(d=><div key={d} style={{textAlign:"center",color:"rgba(255,255,255,0.25)",fontSize:9,fontWeight:700,padding:"4px 0"}}>{d}</div>)}
            {monthDates.map((d,i)=>{
              if(!d) return <div key={"e"+i}/>;
              const ss=scheduleData[d]||[];
              const isToday=d===today;
              const isSel=d===selectedDate;
              return(
                <button key={d} onClick={()=>{setSelectedDate(d);setView("day");}}
                  style={{padding:"5px 2px",borderRadius:8,border:`1px solid ${isSel?"#FFD166":ss.length?"rgba(255,209,102,0.2)":"rgba(255,255,255,0.04)"}`,
                    background:isSel?"rgba(255,209,102,0.2)":isToday?"rgba(255,209,102,0.08)":"transparent",
                    cursor:"pointer",fontFamily:"inherit",textAlign:"center",position:"relative"}}>
                  <div style={{color:isSel?"#FFD166":isToday?"#FFD166":C.t2,fontWeight:isSel||isToday?800:400,fontSize:12}}>{new Date(d+"T12:00:00").getDate()}</div>
                  {ss.length>0&&<div style={{width:4,height:4,borderRadius:"50%",background:"#FFD166",margin:"1px auto 0"}}/>}
                </button>
              );
            })}
          </div>
        </div>
      )}
      {bookingOpen&&(
        <div style={{position:"fixed",inset:0,zIndex:900,background:"rgba(0,0,0,0.7)",backdropFilter:"blur(4px)",display:"flex",alignItems:"flex-end"}} onClick={()=>setBookingOpen(false)}>
          <div style={{width:"100%",maxWidth:430,margin:"0 auto",background:"#050B15",borderRadius:"22px 22px 0 0",padding:"20px 16px 44px",border:"1px solid rgba(255,209,102,0.2)"}} onClick={e=>e.stopPropagation()}>
            <div style={{color:"#FFFDE8",fontWeight:800,fontSize:16,marginBottom:16,direction:"rtl"}}>+ קביעת משחק</div>
            <RefBookingForm RC={{"primary":"#FFD166","cardBorder":"rgba(255,209,102,0.15)"}} onSave={(s)=>{setScheduleData(prev=>({...prev,[s.date]:[...(prev[s.date]||[]),{time:s.time,end:s.end,name:s.name,type:"משחק",color:"#FFD166",sport:"כדורגל",location:"",organizer:"",pay:200,status:"מאושר",participants:[]}].sort((a,b)=>a.time.localeCompare(b.time))}));setBookingOpen(false);}} onClose={()=>setBookingOpen(false)}/>
          </div>
        </div>
      )}
      {selectedGame&&<RefGameDetailModal game={selectedGame} onClose={()=>setSelectedGame(null)}/>}
    </div>
  );
}

function RefBookingForm({RC,onSave,onClose}){
  const C=useC();
  const [name,setName]=useState("");
  const [date,setDate]=useState("2026-03-10");
  const [time,setTime]=useState("17:00");
  const [end,setEnd]=useState("19:00");
  const [sport,setSport]=useState("כדורגל");
  return(
    <div style={{direction:"rtl"}}>
      {[["שם האירוע",name,setName,"text","למשל: כדורגל ליגה א׳"],["תאריך",date,setDate,"date",""],["שעת התחלה",time,setTime,"time",""],["שעת סיום",end,setEnd,"time",""]].map(([l,v,fn,t,ph])=>(
        <div key={l} style={{marginBottom:12}}>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginBottom:5}}>{l}</div>
          <input type={t} value={v} onChange={e=>fn(e.target.value)} placeholder={ph}
            style={{width:"100%",padding:"10px 13px",borderRadius:11,border:`1px solid ${RC.cardBorder}`,
              background:"rgba(255,209,102,0.04)",color:"#FFFDE8",fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}/>
        </div>
      ))}
      <div style={{marginBottom:16}}>
        <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginBottom:5}}>ספורט</div>
        <div style={{display:"flex",gap:6}}>
          {["כדורגל","כדורסל","כדוריד","כדורעף","אחר"].map(s=>(
            <button key={s} onClick={()=>setSport(s)}
              style={{flex:1,padding:"7px 4px",borderRadius:9,border:`1px solid ${sport===s?"#FFD166":"rgba(255,255,255,0.1)"}`,
                background:sport===s?"rgba(255,209,102,0.15)":"transparent",
                color:sport===s?"#FFD166":"rgba(255,255,255,0.4)",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
              {s}
            </button>
          ))}
        </div>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={()=>name&&onSave({name:`${sport} — ${name}`,date,time,end})} disabled={!name}
          style={{flex:2,padding:"12px",borderRadius:13,border:"none",cursor:name?"pointer":"default",
            background:name?"linear-gradient(135deg,#FFD166,#4D9FFF)":"rgba(255,255,255,0.05)",
            color:name?"#000":"rgba(255,255,255,0.3)",fontWeight:900,fontSize:13,fontFamily:"inherit"}}>
          ✓ שמור
        </button>
        <button onClick={onClose} style={{flex:1,padding:"12px",borderRadius:13,border:"1px solid rgba(255,209,102,0.2)",background:"transparent",color:"rgba(255,255,255,0.4)",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>ביטול</button>
      </div>
    </div>
  );
}

