/* ═══════════════════════════════════════════════════════
   REFEREE RANK SYSTEM
   ═══════════════════════════════════════════════════════ */
const REF_RANKS=[
  {id:"rookie",   label:"Rookie",      icon:"🥉", minXP:0,    color:"#A0A0A0", desc:"שופט מתחיל",     perks:["גישה בסיסית למשחקים","₪80-120 למשחק"]},
  {id:"regional", label:"Regional",    icon:"🥈", minXP:500,  color:"#4D9FFF", desc:"שופט אזורי",     perks:["גישה לליגות אזוריות","₪120-200 למשחק","תג מאומת"]},
  {id:"national", label:"National",    icon:"🥇", minXP:1500, color:"#FFD166", desc:"שופט לאומי",     perks:["כל הליגות","₪200-350 למשחק","עדיפות בהצעות","dashboard הכנסות"]},
  {id:"elite",    label:"Elite",       icon:"💎", minXP:3500, color:"#CC44FF", desc:"שופט עילית",     perks:["גמרים ותחרויות","₪350-600 למשחק","premium visibility","bonus 15%"]},
  {id:"pro",      label:"Pro League",  icon:"👑", minXP:7000, color:"#FF9A3C", desc:"שופט פרו-ליג",   perks:["ליגות בינלאומיות","₪600+","brand partnership","מנטורינג"]},
];

function getRefRank(xp){
  let rank=REF_RANKS[0];
  for(const r of REF_RANKS) if(xp>=r.minXP) rank=r;
  return rank;
}
function getNextRefRank(xp){
  return REF_RANKS.find(r=>r.minXP>xp)||null;
}

function calcRefXP({games=0, avgScore=0, yellowCards=0, redCards=0, cleanSheets=0, uniqueSports=1, ratings=0}){
  let xp = 0;
  xp += games * 30;                          // 30 XP per game
  xp += Math.max(0,(avgScore-7)*50);         // bonus for high avg
  xp += cleanSheets * 15;                    // fair play bonus
  xp -= redCards * 20;                       // penalty
  xp += uniqueSports * 40;                   // versatility
  xp += ratings * 5;                         // community engagement
  return Math.max(0, Math.round(xp));
}

