/* ═══════════════════════════════════════════════════════
   PAYMENT SECURITY LAYER — Apple-grade auth
   Face ID → PIN fallback → Session timeout
   ═══════════════════════════════════════════════════════ */

// Stored PIN (mock — in production: hashed in secure enclave)
const WALLET_PIN = "123456"; // demo PIN shown to user
const SESSION_TIMEOUT_MS = 3 * 60 * 1000; // 3 min idle lock

/* ── PIN pad component ── */
function PinPad({onComplete, title, subtitle, color="#00FFB3", onCancel}){
  const [digits,setDigits]=useState([]);
  const [shake,setShake]=useState(false);
  const [attempt,setAttempt]=useState(0);
  const [locked,setLocked]=useState(false);
  const [lockTimer,setLockTimer]=useState(0);

  // countdown if locked
  useEffect(()=>{
    if(!locked)return;
    const iv=setInterval(()=>setLockTimer(t=>{if(t<=1){setLocked(false);setAttempt(0);clearInterval(iv);return 0;}return t-1;}),1000);
    return()=>clearInterval(iv);
  },[locked]);

  function press(d){
    if(locked)return;
    const next=[...digits,d];
    setDigits(next);
    if(next.length===6){
      if(next.join("")===WALLET_PIN){
        onComplete();
      } else {
        setShake(true);
        setTimeout(()=>{setShake(false);setDigits([]);},600);
        const a=attempt+1;
        setAttempt(a);
        if(a>=3){setLocked(true);setLockTimer(30);}
      }
    }
  }
  function del(){setDigits(d=>d.slice(0,-1));}

  const KEYS=[["1",""],["2","ABC"],["3","DEF"],["4","GHI"],["5","JKL"],["6","MNO"],["7","PQRS"],["8","TUV"],["9","WXYZ"],["",""],["0",""],["⌫",""]];

  return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"20px 0 10px",direction:"rtl"}}>
      <div style={{fontSize:40,marginBottom:10}}>🔐</div>
      <div style={{color:"#fff",fontWeight:800,fontSize:17,marginBottom:4,textAlign:"center"}}>{title}</div>
      <div style={{color:"rgba(255,255,255,0.4)",fontSize:12,marginBottom:24,textAlign:"center"}}>{subtitle}</div>

      {locked?(
        <div style={{textAlign:"center",padding:"20px",background:"rgba(255,61,113,0.08)",
          border:"1px solid rgba(255,61,113,0.2)",borderRadius:16,marginBottom:20}}>
          <div style={{color:"#FF3D71",fontWeight:700,fontSize:14,marginBottom:6}}>🔒 חסום זמנית</div>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:12}}>ניסיונות רבים מדי</div>
          <div style={{color:"#FF3D71",fontWeight:900,fontSize:28,marginTop:8}}>{lockTimer}s</div>
        </div>
      ):(
        <>
          {/* Dots */}
          <div style={{display:"flex",gap:14,marginBottom:32,
            animation:shake?"shake 0.5s ease":"none"}}>
            <style>{`@keyframes shake{0%,100%{transform:translateX(0)}20%,60%{transform:translateX(-8px)}40%,80%{transform:translateX(8px)}}`}</style>
            {Array(6).fill(0).map((_,i)=>(
              <div key={i} style={{width:14,height:14,borderRadius:"50%",
                background:i<digits.length?color:"rgba(255,255,255,0.12)",
                border:`2px solid ${i<digits.length?color:"rgba(255,255,255,0.2)"}`,
                transition:"all 0.15s",
                boxShadow:i<digits.length?`0 0 8px ${color}60`:"none"}}/>
            ))}
          </div>

          {/* Keypad */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12,width:"100%",maxWidth:280}}>
            {KEYS.map(([num,sub],i)=>(
              <button key={i} onClick={num==="⌫"?del:num?()=>press(num):undefined}
                disabled={!num&&num!=="⌫"}
                style={{height:68,borderRadius:18,border:"none",cursor:num?"pointer":"default",fontFamily:"inherit",
                  background:num?"rgba(255,255,255,0.07)":"transparent",
                  display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:1,
                  opacity:num?1:0,
                  transition:"background 0.1s, transform 0.1s",
                  transform:"scale(1)",
                  WebkitTapHighlightColor:"transparent"}}
                onMouseDown={e=>{if(num)e.currentTarget.style.background="rgba(255,255,255,0.15)";}}
                onMouseUp={e=>{if(num)e.currentTarget.style.background="rgba(255,255,255,0.07)";}}>
                <span style={{color:"#fff",fontWeight:400,fontSize:26,lineHeight:1}}>{num}</span>
                {sub&&<span style={{color:"rgba(255,255,255,0.3)",fontSize:8,fontWeight:700,letterSpacing:"0.1em"}}>{sub}</span>}
              </button>
            ))}
          </div>
        </>
      )}

      {attempt>0&&!locked&&(
        <div style={{marginTop:14,color:"rgba(255,61,113,0.8)",fontSize:11}}>
          {3-attempt} ניסיון{3-attempt===1?"":"ות"} נותר{3-attempt===1?"":"ים"} לפני נעילה
        </div>
      )}
      {onCancel&&(
        <button onClick={onCancel} style={{marginTop:16,background:"none",border:"none",
          color:"rgba(255,255,255,0.3)",fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>
          ביטול
        </button>
      )}
    </div>
  );
}

/* ── Biometric mock (WebAuthn-style UX) ── */
function BiometricPrompt({onSuccess, onFallback, onCancel, actionLabel, color="#00FFB3"}){
  const [state,setState]=useState("idle"); // idle|scanning|success|fail

  function simulate(){
    setState("scanning");
    setTimeout(()=>{
      // 90% success rate mock
      if(Math.random()>0.1){
        setState("success");
        setTimeout(onSuccess, 600);
      } else {
        setState("fail");
        setTimeout(()=>setState("idle"),1000);
      }
    }, 1200);
  }

  const scanColor = state==="success"?"#00FFB3":state==="fail"?"#FF3D71":color;

  return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"24px 16px 20px",direction:"rtl"}}>
      <div style={{color:"#fff",fontWeight:800,fontSize:16,marginBottom:4,textAlign:"center"}}>
        אמת את זהותך
      </div>
      <div style={{color:"rgba(255,255,255,0.4)",fontSize:12,marginBottom:28,textAlign:"center"}}>
        {actionLabel}
      </div>

      {/* Face ID ring */}
      <div onClick={state==="idle"||state==="fail"?simulate:undefined}
        style={{width:100,height:100,borderRadius:"50%",cursor:"pointer",position:"relative",
          marginBottom:20,display:"flex",alignItems:"center",justifyContent:"center"}}>
        {/* Outer animated ring */}
        <svg width="100" height="100" style={{position:"absolute",inset:0,
          animation:state==="scanning"?"spin 1.2s linear infinite":"none"}}>
          <style>{`@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}`}</style>
          <circle cx="50" cy="50" r="46" fill="none"
            stroke={scanColor} strokeWidth="2.5"
            strokeDasharray={state==="scanning"?"80 210":state==="success"?"290 0":"0 290"}
            strokeLinecap="round" opacity="0.6"
            style={{transition:"stroke 0.3s, stroke-dasharray 0.4s"}}/>
        </svg>
        {/* Icon */}
        <div style={{width:76,height:76,borderRadius:"50%",
          background:state==="success"?`${scanColor}20`:"rgba(255,255,255,0.04)",
          border:`2px solid ${scanColor}30`,
          display:"flex",alignItems:"center",justifyContent:"center",fontSize:34,
          transition:"all 0.3s",
          boxShadow:state==="success"?`0 0 30px ${scanColor}40`:"none"}}>
          {state==="success"?"✓":state==="fail"?"✗":""}
        </div>
      </div>

      <div style={{color:"rgba(255,255,255,0.6)",fontSize:13,marginBottom:6,textAlign:"center",fontWeight:500}}>
        {state==="idle"?"הקש לאימות Face ID":
         state==="scanning"?"סורק...":
         state==="success"?"מאומת ✓":
         "לא זוהית — נסה שוב"}
      </div>
      <div style={{color:"rgba(255,255,255,0.25)",fontSize:11,marginBottom:20,textAlign:"center"}}>
        Face ID · Touch ID
      </div>

      <button onClick={onFallback}
        style={{padding:"10px 24px",borderRadius:12,border:`1px solid rgba(255,255,255,0.1)`,
          background:"rgba(255,255,255,0.04)",color:"rgba(255,255,255,0.5)",fontSize:12,
          fontWeight:600,cursor:"pointer",fontFamily:"inherit",marginBottom:8}}>
        השתמש בקוד
      </button>
      {onCancel&&(
        <button onClick={onCancel}
          style={{background:"none",border:"none",color:"rgba(255,255,255,0.25)",
            fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
          ביטול
        </button>
      )}
    </div>
  );
}

/* ── Confirm action dialog — "Double confirm" like Apple Pay ── */
