/* ─── CROSS-SPORT TRANSFER RULES ─── */
const CROSS_SPORT_MAP=[
  // Running → Football
  {from:{sport:"running",cat:"endurance",attr:"aerobic"},  to:{sport:"football",cat:"physical",attr:"stamina"},  weight:0.4},
  {from:{sport:"running",cat:"speed",attr:"sprint"},       to:{sport:"football",cat:"pace",attr:"sprint"},       weight:0.5},
  {from:{sport:"running",cat:"speed",attr:"tempo"},        to:{sport:"football",cat:"pace",attr:"acceleration"}, weight:0.3},
  // Swimming → Football
  {from:{sport:"swimming",cat:"endurance",attr:"aerobic"}, to:{sport:"football",cat:"physical",attr:"stamina"},  weight:0.3},
  // Cycling → Football
  {from:{sport:"cycling",cat:"endurance",attr:"aerobic"},  to:{sport:"football",cat:"physical",attr:"stamina"},  weight:0.25},
  // Running → Basketball
  {from:{sport:"running",cat:"speed",attr:"sprint"},       to:{sport:"basketball",cat:"athleticism",attr:"speed"},weight:0.45},
  {from:{sport:"running",cat:"endurance",attr:"aerobic"},  to:{sport:"basketball",cat:"athleticism",attr:"stamina"},weight:0.35},
  {from:{sport:"running",cat:"strength",attr:"legs"},      to:{sport:"basketball",cat:"athleticism",attr:"jump"}, weight:0.3},
  // Running → Tennis
  {from:{sport:"running",cat:"speed",attr:"sprint"},       to:{sport:"tennis",cat:"movement",attr:"speed"},      weight:0.5},
  {from:{sport:"running",cat:"endurance",attr:"aerobic"},  to:{sport:"tennis",cat:"mental",attr:"consistency"},  weight:0.3},
  // Swimming → Running
  {from:{sport:"swimming",cat:"endurance",attr:"aerobic"}, to:{sport:"running",cat:"endurance",attr:"aerobic"},  weight:0.35},
  // Cycling → Running
  {from:{sport:"cycling",cat:"endurance",attr:"aerobic"},  to:{sport:"running",cat:"endurance",attr:"aerobic"},  weight:0.4},
  {from:{sport:"cycling",cat:"endurance",attr:"threshold"},to:{sport:"running",cat:"endurance",attr:"threshold"},weight:0.35},
];

function computeCrossBoost(targetSport, activityLog, baseCats){
  const boost={};
  const enabledLog=activityLog.filter(e=>e.enabled!==false&&e.sport!==targetSport);
  for(const entry of enabledLog){
    const rules=CROSS_SPORT_MAP.filter(r=>r.from.sport===entry.sport&&r.to.sport===targetSport);
    for(const rule of rules){
      const fieldMap={"endurance-aerobic":"endurance","endurance-threshold":"endurance","speed-sprint":"speed","speed-tempo":"speed","strength-legs":"endurance","athleticism-speed":"speed","athleticism-jump":"endurance"};
      const key=`${rule.from.cat}-${rule.from.attr}`;
      const field=fieldMap[key]||"endurance";
      const rawVal=entry[field]||75;
      const boostAmt=Math.round(rawVal*rule.weight*0.3);
      const k=`${rule.to.cat}__${rule.to.attr}`;
      boost[k]=(boost[k]||0)+boostAmt;
    }
  }
  return boost;
}

function applyBoostToCats(baseCats, boost){
  return baseCats.map(cat=>({
    ...cat,
    attrs:cat.attrs.map(attr=>{
      const k=`${cat.id}__${attr.id}`;
      const boostAmt=boost[k]||0;
      if(!boostAmt)return attr;
      return{...attr,val:Math.min(99,attr.val+boostAmt),boosted:true,boostAmt};
    }),
  }));
}

/* ── CROSS-SPORT ACTIVITY MANAGER ── */
function CrossSportManager({sport, activityLog, onUpdate}){
  const C=useC();
  const relevantLog = activityLog.filter(e=>e.sport!==sport&&
    CROSS_SPORT_MAP.some(r=>r.from.sport===e.sport&&r.to.sport===sport));

  if(!relevantLog.length) return(
    <div style={{background:C.card,borderRadius:16,padding:"14px 16px",direction:"rtl",marginBottom:12}}>
      <div style={{color:C.t1,fontWeight:700,fontSize:14,marginBottom:4}}>🔗 סנכרון ספורט</div>
      <div style={{color:C.t3,fontSize:12}}>אין פעילויות מספורטים אחרים שמשפיעות על {sport}</div>
    </div>
  );

  const enabledCount = relevantLog.filter(e=>e.enabled).length;

  return(
    <div style={{background:C.card,borderRadius:16,padding:"14px 16px",direction:"rtl",marginBottom:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
        <div>
          <div style={{color:C.t1,fontWeight:800,fontSize:14}}>🔗 ספורטים מקושרים</div>
          <div style={{color:C.t3,fontSize:11,marginTop:1}}>{enabledCount}/{relevantLog.length} פעילויות פעילות</div>
        </div>
        <div style={{background:`${C.primary}18`,borderRadius:20,padding:"4px 10px"}}>
          <span style={{color:C.primary,fontSize:11,fontWeight:700}}>+{enabledCount>0?Math.round(enabledCount*1.5):0} לכרטיס</span>
        </div>
      </div>
      <div style={{fontSize:11,color:C.t3,marginBottom:10,
        background:`rgba(255,255,255,0.04)`,borderRadius:10,padding:"7px 10px",lineHeight:1.6}}>
        💡 פעילויות מסומנות כ"כבוי" לא ישפיעו על כרטיס השחקן שלך.
        הוצא ריצות קלות שלא מייצגות את הרמה האמיתית שלך.
      </div>
      {relevantLog.map(entry=>{
        const rules = CROSS_SPORT_MAP.filter(r=>r.from.sport===entry.sport&&r.to.sport===sport);
        return(
          <div key={entry.id} style={{display:"flex",alignItems:"center",gap:10,
            padding:"9px 10px",borderRadius:12,marginBottom:6,
            background:entry.enabled?"rgba(0,192,127,0.07)":"rgba(255,255,255,0.03)",
            border:`1px solid ${entry.enabled?"rgba(0,192,127,0.2)":"rgba(255,255,255,0.05)"}`}}>
            <div style={{flex:1}}>
              <div style={{display:"flex",gap:6,alignItems:"center"}}>
                <span style={{fontSize:12}}>
                  {entry.sport==="running"?"🏃":entry.sport==="cycling"?"🚴":entry.sport==="swimming"?"🏊":"🏅"}
                </span>
                <span style={{color:C.t1,fontSize:12,fontWeight:600}}>{entry.label}</span>
              </div>
              <div style={{display:"flex",gap:8,marginTop:3}}>
                <span style={{color:C.t3,fontSize:10}}>{entry.date}</span>
                <span style={{color:"#60AFFF",fontSize:10}}>סיבולת: {entry.endurance}</span>
                <span style={{color:"#FF6B2B",fontSize:10}}>מהירות: {entry.speed}</span>
              </div>
              {entry.note&&<div style={{color:C.accent,fontSize:10,marginTop:2}}>⚠️ {entry.note}</div>}
              <div style={{display:"flex",flexWrap:"wrap",gap:3,marginTop:4}}>
                {rules.map((r,i)=>(
                  <span key={i} style={{background:"rgba(255,255,255,0.06)",borderRadius:8,
                    padding:"2px 7px",color:C.t3,fontSize:9}}>
                    {r.from.attr}→{r.to.cat} (+{Math.round(r.weight*10)})
                  </span>
                ))}
              </div>
            </div>
            <button onClick={()=>onUpdate(entry.id,!entry.enabled)}
              style={{width:44,height:24,borderRadius:12,border:"none",cursor:"pointer",
                background:entry.enabled?C.primary:"rgba(255,255,255,0.1)",
                position:"relative",flexShrink:0,transition:"all 0.2s"}}>
              <div style={{position:"absolute",top:2,
                left:entry.enabled?22:2,
                width:20,height:20,borderRadius:"50%",background:"#fff",transition:"left 0.2s"}}/>
            </button>
          </div>
        );
      })}
    </div>
  );
}

/* ── USER SWITCHER PILL (shown in header area) ── */
