function AnimBar({pct,color,delay=0,height=8}){
  const [w,setW]=useState(0);
  useEffect(()=>{const t=setTimeout(()=>setW(pct),delay+80);return()=>clearTimeout(t);},[pct,delay]);
  return(
    <div style={{height,background:"rgba(255,255,255,0.06)",borderRadius:height/2,overflow:"hidden"}}>
      <div style={{height:"100%",width:`${w}%`,background:color,borderRadius:height/2,transition:"width 1s cubic-bezier(0.34,1.56,0.64,1)"}}/>
    </div>
  );
}

function AnimNumber({target,delay=0,suffix=""}){
  const [val,setVal]=useState(0);
  useEffect(()=>{
    const t=setTimeout(()=>{
      const dur=900,steps=40,inc=target/steps;
      let cur=0,s=0;
      const iv=setInterval(()=>{cur=Math.min(cur+inc,target);setVal(Math.round(cur));s++;if(s>=steps){clearInterval(iv);setVal(target);}},dur/steps);
      return()=>clearInterval(iv);
    },delay);
    return()=>clearTimeout(t);
  },[target,delay]);
  return <span>{val}{suffix}</span>;
}

function RadialProgress({pct,color,size=80,stroke=7,children}){
  const [p,setP]=useState(0);
  useEffect(()=>{const t=setTimeout(()=>setP(pct),100);return()=>clearTimeout(t);},[pct]);
  const r=size/2-stroke; const circ=2*Math.PI*r;
  return(
    <div style={{position:"relative",width:size,height:size}}>
      <svg width={size} height={size} style={{transform:"rotate(-90deg)"}}>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth={stroke}/>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth={stroke}
          strokeDasharray={circ} strokeDashoffset={circ*(1-p/100)}
          strokeLinecap="round" style={{transition:"stroke-dashoffset 1.2s cubic-bezier(0.34,1.2,0.64,1)"}}/>
      </svg>
      <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
        {children}
      </div>
    </div>
  );
}

function MiniBarChart({data,color,label}){
  const [mounted,setMounted]=useState(false);
  useEffect(()=>{const t=setTimeout(()=>setMounted(true),150);return()=>clearTimeout(t);},[]);
  const max=Math.max(...data.map(d=>d.v),1);
  return(
    <div>
      <div style={{display:"flex",alignItems:"flex-end",gap:4,height:60,marginBottom:6}}>
        {data.map((d,i)=>(
          <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
            <div style={{width:"100%",background:color,borderRadius:"3px 3px 0 0",
              height:mounted?`${(d.v/max)*52}px`:"0px",
              transition:`height 0.8s cubic-bezier(0.34,1.2,0.64,1) ${i*60}ms`,
              minHeight:mounted&&d.v>0?4:0}}/>
          </div>
        ))}
      </div>
      <div style={{display:"flex",gap:4}}>
        {data.map((d,i)=>(
          <div key={i} style={{flex:1,textAlign:"center",color:"rgba(255,255,255,0.3)",fontSize:8}}>{d.l}</div>
        ))}
      </div>
    </div>
  );
}

