/* ─── TIME CAPSULE ─── */
function TimeCapsuleTab({C}){
  const [capsules,setCapsules]=useState(()=>{
    try{const s=LS.get("plyr_capsules",null);return s?JSON.parse(s):[];}catch{return [];}
  });
  const [form,setForm]=useState({goal:"",sport:"football",date:"",note:""});
  const [addOpen,setAddOpen]=useState(false);
  const [openedId,setOpenedId]=useState(null);
  const today=new Date().toISOString().slice(0,10);

  function save(next){setCapsules(next);try{LS.set("plyr_capsules",JSON.stringify(next));}catch{}}
  function addCapsule(){
    if(!form.goal||!form.date) return;
    save([...capsules,{id:Date.now(),goal:form.goal,sport:form.sport,date:form.date,note:form.note,created:today,opened:false}]);
    setForm({goal:"",sport:"football",date:"",note:""});
    setAddOpen(false);
  }
  function openCapsule(id){
    save(capsules.map(c=>c.id===id?{...c,opened:true}:c));
    setOpenedId(id);
  }

  const ready=capsules.filter(c=>c.date<=today&&!c.opened);
  const upcoming=capsules.filter(c=>c.date>today);
  const opened=capsules.filter(c=>c.opened);

  return(
    <div style={{direction:"rtl"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
        <div style={{color:C.t1,fontWeight:800,fontSize:14}}>⏳ קפסולת זמן</div>
        <button onClick={()=>setAddOpen(true)}
          style={{padding:"6px 14px",borderRadius:20,border:`1px solid ${C.primary}44`,
            background:`${C.primary}15`,color:C.primary,fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>
          + קפסולה חדשה
        </button>
      </div>

      {/* Ready to open */}
      {ready.length>0&&(
        <div style={{marginBottom:16}}>
          <div style={{color:"#FFD166",fontWeight:700,fontSize:11,marginBottom:8}}>🔓 מוכנות לפתיחה!</div>
          {ready.map(c=>(
            <div key={c.id} style={{background:"linear-gradient(135deg,rgba(255,209,102,0.12),rgba(255,209,102,0.05))",
              border:"1px solid rgba(255,209,102,0.35)",borderRadius:16,padding:"14px",marginBottom:10,
              animation:"popIn 0.5s ease both",boxShadow:"0 0 24px rgba(255,209,102,0.15)"}}>
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                <span style={{fontSize:26}}>📬</span>
                <div>
                  <div style={{color:"#FFD166",fontWeight:800,fontSize:13}}>מכתב מהעבר</div>
                  <div style={{color:"rgba(255,255,255,0.4)",fontSize:10}}>נכתב ב-{c.created} · ל-{c.date}</div>
                </div>
              </div>
              {openedId===c.id
                ?<div>
                  <div style={{color:"rgba(255,255,255,0.7)",fontSize:13,lineHeight:1.7,background:"rgba(0,0,0,0.2)",borderRadius:10,padding:"10px 12px",marginBottom:10}}>
                    🎯 <strong style={{color:"#FFD166"}}>{c.goal}</strong><br/>
                    {c.note&&<span style={{color:"rgba(255,255,255,0.5)",fontSize:12}}>{c.note}</span>}
                  </div>
                  <div style={{background:"rgba(0,255,179,0.08)",border:"1px solid rgba(0,255,179,0.2)",borderRadius:10,padding:"10px 12px"}}>
                    <div style={{color:"#00FFB3",fontWeight:700,fontSize:12,marginBottom:4}}>הגעת למטרה? ✨</div>
                    <div style={{display:"flex",gap:8}}>
                      <button onClick={()=>save(capsules.map(cap=>cap.id===c.id?{...cap,result:"yes"}:cap))}
                        style={{flex:1,padding:"8px",borderRadius:10,border:"1px solid rgba(0,255,179,0.3)",background:c.result==="yes"?"rgba(0,255,179,0.2)":"transparent",color:"#00FFB3",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
                        ✅ כן!
                      </button>
                      <button onClick={()=>save(capsules.map(cap=>cap.id===c.id?{...cap,result:"no"}:cap))}
                        style={{flex:1,padding:"8px",borderRadius:10,border:"1px solid rgba(255,61,113,0.3)",background:c.result==="no"?"rgba(255,61,113,0.1)":"transparent",color:"#FF3D71",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
                        🔄 עדיין בדרך
                      </button>
                    </div>
                  </div>
                </div>
                :<button onClick={()=>openCapsule(c.id)}
                  style={{width:"100%",padding:"10px",borderRadius:12,border:"1px solid rgba(255,209,102,0.4)",
                    background:"rgba(255,209,102,0.1)",color:"#FFD166",fontWeight:800,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>
                  📨 פתח את הקפסולה
                </button>
              }
            </div>
          ))}
        </div>
      )}

      {/* Upcoming */}
      {upcoming.length>0&&(
        <div style={{marginBottom:16}}>
          <div style={{color:C.t3,fontWeight:700,fontSize:11,marginBottom:8}}>🔒 ממתינות לפתיחה</div>
          {upcoming.map(c=>{
            const daysLeft=Math.ceil((new Date(c.date)-new Date(today))/(1000*60*60*24));
            return(
              <div key={c.id} style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:14,padding:"12px 14px",marginBottom:8,
                display:"flex",alignItems:"center",gap:12}}>
                <div style={{width:44,height:44,borderRadius:12,background:`${C.primary}15`,border:`1px solid ${C.primary}30`,
                  display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>
                  {SPORT_ICONS[c.sport]||"🎯"}
                </div>
                <div style={{flex:1}}>
                  <div style={{color:C.t1,fontWeight:700,fontSize:12}}>{c.goal}</div>
                  <div style={{color:C.t3,fontSize:10,marginTop:2}}>נפתחת ב-{c.date}</div>
                </div>
                <div style={{textAlign:"center",flexShrink:0}}>
                  <div style={{color:C.primary,fontWeight:800,fontSize:16}}>{daysLeft}</div>
                  <div style={{color:C.t3,fontSize:9}}>ימים</div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Opened history */}
      {opened.length>0&&(
        <div style={{marginBottom:16}}>
          <div style={{color:C.t3,fontWeight:700,fontSize:11,marginBottom:8}}>📖 היסטוריה</div>
          {opened.map(c=>(
            <div key={c.id} style={{background:"rgba(255,255,255,0.02)",border:`1px solid ${C.border}`,borderRadius:12,padding:"10px 14px",marginBottom:7,
              display:"flex",alignItems:"center",gap:10}}>
              <span style={{fontSize:18}}>{c.result==="yes"?"✅":c.result==="no"?"🔄":"📭"}</span>
              <div style={{flex:1}}>
                <div style={{color:C.t2,fontSize:12}}>{c.goal}</div>
                <div style={{color:C.t3,fontSize:9,marginTop:1}}>{c.created} ← {c.date}</div>
              </div>
            </div>
          ))}
        </div>
      )}

      {capsules.length===0&&(
        <div style={{textAlign:"center",padding:"40px 20px"}}>
          <div style={{fontSize:48,marginBottom:12}}>⏳</div>
          <div style={{color:C.t3,fontSize:13,marginBottom:6}}>כתוב מכתב לעצמך</div>
          <div style={{color:"rgba(255,255,255,0.2)",fontSize:11,marginBottom:16}}>הגדר מטרה, קבע תאריך — האפליקציה תזכיר לך</div>
          <button onClick={()=>setAddOpen(true)}
            style={{padding:"10px 22px",borderRadius:20,border:`1px solid ${C.primary}44`,background:`${C.primary}15`,color:C.primary,fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
            צור קפסולה ראשונה
          </button>
        </div>
      )}

      {/* Add sheet */}
      {addOpen&&(
        <div style={{position:"fixed",inset:0,zIndex:900,background:"rgba(0,0,0,0.75)",backdropFilter:"blur(4px)",display:"flex",alignItems:"flex-end"}} onClick={()=>setAddOpen(false)}>
          <div style={{width:"100%",maxWidth:430,margin:"0 auto",background:"#050B15",borderRadius:"22px 22px 0 0",padding:"20px 16px 44px",border:`1px solid ${C.primary}22`}} onClick={e=>e.stopPropagation()}>
            <div style={{color:C.t1,fontWeight:800,fontSize:16,marginBottom:4,direction:"rtl"}}>⏳ קפסולה חדשה</div>
            <div style={{color:"rgba(255,255,255,0.3)",fontSize:11,marginBottom:16,direction:"rtl"}}>כתוב מטרה לעצמך — תגלה אותה בתאריך שתקבע</div>
            <div style={{direction:"rtl"}}>
              <div style={{display:"flex",gap:5,marginBottom:12,overflowX:"auto",paddingBottom:2}}>
                {SPORT_OPTIONS.map(s=>(
                  <button key={s} onClick={()=>setForm(f=>({...f,sport:s}))}
                    style={{flexShrink:0,padding:"5px 10px",borderRadius:9,border:`1px solid ${form.sport===s?C.primary+"66":"rgba(255,255,255,0.1)"}`,
                      background:form.sport===s?`${C.primary}20`:"transparent",
                      color:form.sport===s?C.primary:"rgba(255,255,255,0.4)",fontSize:11,cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>
                    {SPORT_ICONS[s]} {SPORT_LABELS[s]}
                  </button>
                ))}
              </div>
              {[["🎯 המטרה שלי",form.goal,"text",v=>setForm(f=>({...f,goal:v})),"לדוגמה: להגיע ל-ELO 1700 ולשחק בליגה א׳"],
                ["📅 פתח אותה בתאריך",form.date,"date",v=>setForm(f=>({...f,date:v})),""],
              ].map(([l,v,t,fn,ph])=>(
                <div key={l} style={{marginBottom:12}}>
                  <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginBottom:5}}>{l}</div>
                  <input type={t} value={v} onChange={e=>fn(e.target.value)} placeholder={ph}
                    style={{width:"100%",padding:"10px 13px",borderRadius:11,border:`1px solid ${C.primary}22`,
                      background:`${C.primary}05`,color:"#fff",fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}/>
                </div>
              ))}
              <div style={{marginBottom:16}}>
                <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginBottom:5}}>💬 הוסף הודעה לעצמך (אופציונלי)</div>
                <textarea value={form.note} onChange={e=>setForm(f=>({...f,note:e.target.value}))}
                  placeholder="מה חשוב לך עכשיו? מה תרצה לזכור?"
                  rows={3} style={{width:"100%",padding:"10px 13px",borderRadius:11,border:`1px solid ${C.primary}22`,
                    background:`${C.primary}05`,color:"#fff",fontSize:12,outline:"none",fontFamily:"inherit",
                    boxSizing:"border-box",resize:"none",lineHeight:1.6}}/>
              </div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={addCapsule} disabled={!form.goal||!form.date}
                  style={{flex:2,padding:"12px",borderRadius:13,border:"none",cursor:form.goal&&form.date?"pointer":"default",
                    background:form.goal&&form.date?`linear-gradient(135deg,${C.primary},${C.blue})`:"rgba(255,255,255,0.05)",
                    color:form.goal&&form.date?"#000":"rgba(255,255,255,0.3)",fontWeight:900,fontSize:13,fontFamily:"inherit"}}>
                  🔒 אטום קפסולה
                </button>
                <button onClick={()=>setAddOpen(false)} style={{flex:1,padding:"12px",borderRadius:13,border:`1px solid ${C.primary}22`,background:"transparent",color:"rgba(255,255,255,0.4)",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>ביטול</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── PERFORMANCE STATE (watch + health integration) ─── */
function PerformanceStateTab({C}){
  const [healthData,setHealthData]=useState(()=>{
    try{const s=LS.get("plyr_health",null);return s?JSON.parse(s):{sleep:7,battery:82,hrv:58,steps:6400,stress:3};}catch{return {sleep:7,battery:82,hrv:58,steps:6400,stress:3};}
  });
  const [syncing,setSyncing]=useState(false);
  const [lastSync,setLastSync]=useState("לפני 12 דקות");
  const [manualOpen,setManualOpen]=useState(false);
  const [draft,setDraft]=useState(healthData);

  function calcScore(d){
    let s=0;
    s+=d.sleep>=8?25:d.sleep>=7?20:d.sleep>=6?12:5;
    s+=d.battery>=90?25:d.battery>=75?20:d.battery>=60?13:5;
    s+=d.hrv>=65?25:d.hrv>=55?20:d.hrv>=45?13:5;
    s+=d.stress<=2?25:d.stress<=3?18:d.stress<=4?10:3;
    return s;
  }

  const score=calcScore(healthData);
  const stateInfo=score>=85?{label:"יום מצוין 🚀",color:"#00FFB3",desc:"הגוף שלך במצב שיא — זה הזמן לאתגר!",emoji:"🔋"}
    :score>=65?{label:"יום טוב 💪",color:C.primary,desc:"ביצועים טובים, תן הכל",emoji:"⚡"}
    :score>=45?{label:"יום בינוני 🌤",color:"#FFD166",desc:"התאמן אבל אל תגזים, הגוף מתאושש",emoji:"🌤"}
    :{label:"יום מנוחה 😴",color:"rgba(255,100,100,0.9)",desc:"הגוף מבקש מנוחה — עדיף ריקברי היום",emoji:"🛌"};

  function syncWatch(){
    setSyncing(true);
    setTimeout(()=>{
      const simulated={
        sleep:6+Math.random()*3,
        battery:55+Math.floor(Math.random()*45),
        hrv:45+Math.floor(Math.random()*35),
        steps:3000+Math.floor(Math.random()*8000),
        stress:1+Math.floor(Math.random()*5),
      };
      simulated.sleep=Math.round(simulated.sleep*10)/10;
      setHealthData(simulated);
      setDraft(simulated);
      setLastSync("עכשיו");
      setSyncing(false);
      try{LS.set("plyr_health",JSON.stringify(simulated));}catch{}
    },1800);
  }

  function saveManual(){
    setHealthData(draft);
    try{LS.set("plyr_health",JSON.stringify(draft));}catch{}
    setManualOpen(false);
  }

  const metrics=[
    {key:"sleep",label:"שינה",value:healthData.sleep+"h",icon:"😴",max:10,val:healthData.sleep,good:healthData.sleep>=7,color:"#4D9FFF"},
    {key:"battery",label:"Body Battery",value:healthData.battery+"%",icon:"🔋",max:100,val:healthData.battery,good:healthData.battery>=75,color:"#00FFB3"},
    {key:"hrv",label:"HRV",value:healthData.hrv+"ms",icon:"❤️",max:100,val:healthData.hrv,good:healthData.hrv>=55,color:"#FF6B9D"},
    {key:"steps",label:"צעדים",value:(healthData.steps/1000).toFixed(1)+"K",icon:"👟",max:15000,val:healthData.steps,good:healthData.steps>=8000,color:"#FFD166"},
    {key:"stress",label:"סטרס",value:healthData.stress+"/5",icon:"🧘",max:5,val:5-healthData.stress,good:healthData.stress<=3,color:"#CC44FF"},
  ];

  return(
    <div style={{direction:"rtl"}}>
      {/* Main state card */}
      <div style={{background:`linear-gradient(135deg,${stateInfo.color}18,${stateInfo.color}08)`,
        border:`1px solid ${stateInfo.color}35`,borderRadius:20,padding:"20px",marginBottom:14,
        boxShadow:`0 0 32px ${stateInfo.color}15`,textAlign:"center"}}>
        <div style={{fontSize:44,marginBottom:8}}>{stateInfo.emoji}</div>
        <div style={{color:stateInfo.color,fontWeight:900,fontSize:22,marginBottom:4}}>{stateInfo.label}</div>
        <div style={{color:"rgba(255,255,255,0.5)",fontSize:12,marginBottom:14}}>{stateInfo.desc}</div>
        <div style={{display:"flex",justifyContent:"center",alignItems:"center",gap:12,marginBottom:16}}>
          <div style={{width:80,height:80,position:"relative"}}>
            <RadialProgress pct={score} color={stateInfo.color} size={80} stroke={7}>
              <div style={{color:stateInfo.color,fontWeight:900,fontSize:18,lineHeight:1}}>{score}</div>
              <div style={{color:"rgba(255,255,255,0.4)",fontSize:8}}>ציון</div>
            </RadialProgress>
          </div>
        </div>
        <div style={{display:"flex",gap:8,justifyContent:"center"}}>
          <button onClick={syncWatch} disabled={syncing}
            style={{padding:"9px 18px",borderRadius:20,border:`1px solid ${stateInfo.color}44`,
              background:`${stateInfo.color}18`,color:stateInfo.color,fontWeight:700,fontSize:11,
              cursor:syncing?"default":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:6}}>
            {syncing?<span style={{animation:"spin 1s linear infinite",display:"inline-block"}}>⟳</span>:"⌚"}
            {syncing?"מסנכרן...":"סנכרן שעון"}
          </button>
          <button onClick={()=>setManualOpen(true)}
            style={{padding:"9px 18px",borderRadius:20,border:"1px solid rgba(255,255,255,0.12)",
              background:"rgba(255,255,255,0.05)",color:"rgba(255,255,255,0.5)",fontWeight:700,fontSize:11,
              cursor:"pointer",fontFamily:"inherit"}}>
            ✏️ הזן ידנית
          </button>
        </div>
        <div style={{color:"rgba(255,255,255,0.2)",fontSize:9,marginTop:8}}>סונכרן לאחרונה: {lastSync}</div>
      </div>

      {/* Metrics grid */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,marginBottom:14}}>
        {metrics.map((m,i)=>(
          <div key={m.key} style={{background:C.card,border:`1px solid ${m.good?m.color+"33":C.border}`,borderRadius:14,padding:"12px",
            animation:`popIn 0.4s ease ${i*60}ms both`}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
              <div>
                <div style={{color:"rgba(255,255,255,0.35)",fontSize:9,fontWeight:600,marginBottom:2}}>{m.label}</div>
                <div style={{color:m.good?m.color:"rgba(255,255,255,0.6)",fontWeight:900,fontSize:18}}>{m.value}</div>
              </div>
              <span style={{fontSize:20}}>{m.icon}</span>
            </div>
            <AnimBar pct={(m.val/m.max)*100} color={m.good?`linear-gradient(90deg,${m.color},${m.color}88)`:"linear-gradient(90deg,rgba(255,255,255,0.2),rgba(255,255,255,0.1))"} delay={i*60+200} height={4}/>
          </div>
        ))}
      </div>

      {/* Watch models support */}
      <div style={{background:"rgba(255,255,255,0.02)",border:`1px solid ${C.border}`,borderRadius:14,padding:"12px 14px",marginBottom:10}}>
        <div style={{color:C.t3,fontSize:10,fontWeight:700,marginBottom:8}}>⌚ שעונים נתמכים</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          {[["Garmin","#00A3E0"],["Apple Watch","#A8A9AD"],["Fitbit","#00B0B9"],["Samsung","#1428A0"],["Polar","#D91F26"]].map(([name,col])=>(
            <div key={name} style={{background:`${col}15`,border:`1px solid ${col}30`,borderRadius:8,padding:"4px 10px"}}>
              <span style={{color:col,fontSize:10,fontWeight:700}}>{name}</span>
            </div>
          ))}
        </div>
        <div style={{color:"rgba(255,255,255,0.2)",fontSize:9,marginTop:8}}>* סנכרון אוטומטי דרך Health API / Garmin Connect</div>
      </div>

      {/* Manual input sheet */}
      {manualOpen&&(
        <div style={{position:"fixed",inset:0,zIndex:900,background:"rgba(0,0,0,0.75)",backdropFilter:"blur(4px)",display:"flex",alignItems:"flex-end"}} onClick={()=>setManualOpen(false)}>
          <div style={{width:"100%",maxWidth:430,margin:"0 auto",background:"#050B15",borderRadius:"22px 22px 0 0",padding:"20px 16px 44px",border:`1px solid ${C.primary}22`}} onClick={e=>e.stopPropagation()}>
            <div style={{color:C.t1,fontWeight:800,fontSize:16,marginBottom:16,direction:"rtl"}}>✏️ הזנה ידנית</div>
            <div style={{direction:"rtl"}}>
              {[["😴 שעות שינה",draft.sleep,"sleep",0,12,0.5],["🔋 Body Battery",draft.battery,"battery",0,100,5],["❤️ HRV (ms)",draft.hrv,"hrv",20,120,1],["🧘 רמת סטרס (1-5)",draft.stress,"stress",1,5,1]].map(([l,v,k,mn,mx,st])=>(
                <div key={k} style={{marginBottom:14}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
                    <span style={{color:"rgba(255,255,255,0.5)",fontSize:12}}>{l}</span>
                    <span style={{color:C.primary,fontWeight:700,fontSize:12}}>{v}</span>
                  </div>
                  <input type="range" min={mn} max={mx} step={st} value={v}
                    onChange={e=>setDraft(d=>({...d,[k]:parseFloat(e.target.value)}))}
                    style={{width:"100%",accentColor:C.primary}}/>
                </div>
              ))}
              <div style={{display:"flex",gap:8,marginTop:8}}>
                <button onClick={saveManual} style={{flex:2,padding:"12px",borderRadius:13,border:"none",cursor:"pointer",background:`linear-gradient(135deg,${C.primary},${C.blue})`,color:"#000",fontWeight:900,fontSize:13,fontFamily:"inherit"}}>שמור</button>
                <button onClick={()=>setManualOpen(false)} style={{flex:1,padding:"12px",borderRadius:13,border:`1px solid ${C.border}`,background:"transparent",color:"rgba(255,255,255,0.4)",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>ביטול</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── SPORTS DNA ─── */
function SportsDNATab({C}){
  const {user:prof}=useUser();
  const [loading,setLoading]=useState(false);
  const [analysis,setAnalysis]=useState(()=>{try{const s=LS.get("plyr_dna",null);return s?JSON.parse(s):null;}catch{return null;}});
  const [error,setError]=useState(null);

  async function generateDNA(){
    setLoading(true);
    setError(null);
    try{
      const prompt=`אתה מנתח DNA ספורטיבי של שחקן. על בסיס הנתונים הבאים תנתח את פרופיל השחקן:
שם: ${prof.name}
ELO: ${prof.elo||1540}
XP: ${prof.xp||3200}
ניצחונות: ${prof.wins||48}, הפסדות: ${prof.losses||22}, תיקו: ${prof.draws||11}
ספורטים: כדורגל, ריצה

החזר JSON בלבד (ללא מרקדאון) עם המבנה הבא:
{
  "archetype": "שם הארכיטיפ (למשל: הלוחם השקט / מנהיג הקבוצה / הגאון הטקטי)",
  "archetypeEmoji": "אמוג׳י אחד",
  "summary": "תיאור קצר של 2 משפטים בעברית על הסגנון הייחודי",
  "strengths": ["חוזק 1","חוזק 2","חוזק 3"],
  "patterns": ["דפוס התנהגות 1","דפוס 2","דפוס 3"],
  "insight": "תובנה מפתיעה אחת שהשחקן לא יצפה לה",
  "scores": {"mentality": 82, "technique": 74, "consistency": 68, "leadership": 79, "growth": 91}
}`;
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})});
      const data=await res.json();
      const text=data.content?.filter(b=>b.type==="text").map(b=>b.text).join("")||"";
      const clean=text.replace(/```json|```/g,"").trim();
      const parsed=JSON.parse(clean);
      setAnalysis(parsed);
      try{LS.set("plyr_dna",JSON.stringify(parsed));}catch{}
    }catch(e){setError("שגיאה בניתוח, נסה שוב");}
    setLoading(false);
  }

  const dnaScoreColors={"mentality":"#FF6B9D","technique":C.primary,"consistency":"#4D9FFF","leadership":"#FFD166","growth":"#00FFB3"};
  const dnaScoreLabels={"mentality":"מנטאליות","technique":"טכניקה","consistency":"עקביות","leadership":"מנהיגות","growth":"צמיחה"};

  return(
    <div style={{direction:"rtl"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
        <div style={{color:C.t1,fontWeight:800,fontSize:14}}>🧬 DNA ספורטיבי</div>
        <button onClick={generateDNA} disabled={loading}
          style={{padding:"6px 14px",borderRadius:20,border:`1px solid ${C.primary}44`,
            background:`${C.primary}15`,color:C.primary,fontWeight:700,fontSize:11,
            cursor:loading?"default":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:5}}>
          {loading?<span style={{animation:"spin 1s linear infinite",display:"inline-block"}}>⟳</span>:"🤖"}
          {loading?"מנתח...":analysis?"נתח מחדש":"נתח את ה-DNA שלי"}
        </button>
      </div>

      {!analysis&&!loading&&(
        <div style={{textAlign:"center",padding:"40px 20px"}}>
          <div style={{fontSize:52,marginBottom:12}}>🧬</div>
          <div style={{color:C.t2,fontSize:13,marginBottom:6}}>מה ה-DNA הספורטיבי שלך?</div>
          <div style={{color:"rgba(255,255,255,0.2)",fontSize:11,lineHeight:1.7,marginBottom:20}}>
            AI מנתח את דפוסי הביצועים שלך,<br/>מזהה את הארכיטיפ הייחודי שלך<br/>ומגלה תובנות שלא ידעת על עצמך
          </div>
          <button onClick={generateDNA}
            style={{padding:"12px 28px",borderRadius:20,border:"none",cursor:"pointer",
              background:`linear-gradient(135deg,${C.primary},${C.blue})`,
              color:"#000",fontWeight:900,fontSize:13,fontFamily:"inherit"}}>
            🧬 גלה את ה-DNA שלי
          </button>
        </div>
      )}

      {loading&&(
        <div style={{textAlign:"center",padding:"50px 20px"}}>
          <div style={{fontSize:48,marginBottom:16,animation:"spin 2s linear infinite",display:"inline-block"}}>🧬</div>
          <div style={{color:C.primary,fontWeight:700,fontSize:14,marginBottom:8}}>מנתח את הדפוסים שלך...</div>
          <div style={{color:C.t3,fontSize:11}}>AI בוחן אלפי נקודות נתון</div>
        </div>
      )}

      {error&&<div style={{background:"rgba(255,61,113,0.1)",border:"1px solid rgba(255,61,113,0.2)",borderRadius:12,padding:"12px",color:"#FF3D71",fontSize:12,textAlign:"center",marginBottom:12}}>{error}</div>}

      {analysis&&!loading&&(
        <div>
          {/* Archetype card */}
          <div style={{background:`linear-gradient(135deg,${C.primary}18,${C.blue}10)`,border:`1px solid ${C.primary}35`,borderRadius:20,padding:"20px",marginBottom:14,textAlign:"center",boxShadow:`0 0 32px ${C.primary}15`}}>
            <div style={{fontSize:52,marginBottom:8}}>{analysis.archetypeEmoji}</div>
            <div style={{color:C.primary,fontWeight:900,fontSize:20,marginBottom:8}}>{analysis.archetype}</div>
            <div style={{color:"rgba(255,255,255,0.6)",fontSize:12,lineHeight:1.7}}>{analysis.summary}</div>
          </div>

          {/* DNA scores radar-style */}
          <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:17,padding:"16px",marginBottom:12}}>
            <div style={{color:C.t1,fontWeight:800,fontSize:13,marginBottom:14}}>📊 מפת DNA</div>
            {analysis.scores&&Object.entries(analysis.scores).map(([k,v],i)=>(
              <div key={k} style={{marginBottom:10}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                  <span style={{color:C.t2,fontSize:12}}>{dnaScoreLabels[k]||k}</span>
                  <span style={{color:dnaScoreColors[k]||C.primary,fontWeight:700,fontSize:12}}>{v}</span>
                </div>
                <AnimBar pct={v} color={`linear-gradient(90deg,${dnaScoreColors[k]||C.primary},${dnaScoreColors[k]||C.primary}88)`} delay={i*80} height={6}/>
              </div>
            ))}
          </div>

          {/* Strengths */}
          <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:17,padding:"16px",marginBottom:12}}>
            <div style={{color:C.t1,fontWeight:800,fontSize:13,marginBottom:12}}>💪 חוזקות ייחודיות</div>
            {(analysis.strengths||[]).map((s,i)=>(
              <div key={i} style={{display:"flex",gap:10,alignItems:"flex-start",marginBottom:8,padding:"8px 10px",background:"rgba(255,255,255,0.03)",borderRadius:10,border:`1px solid ${C.border}`}}>
                <span style={{color:C.primary,fontWeight:800,fontSize:12,minWidth:16}}>{i+1}.</span>
                <span style={{color:C.t2,fontSize:12,lineHeight:1.5}}>{s}</span>
              </div>
            ))}
          </div>

          {/* Behavioral patterns */}
          <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:17,padding:"16px",marginBottom:12}}>
            <div style={{color:C.t1,fontWeight:800,fontSize:13,marginBottom:12}}>🔄 דפוסי התנהגות</div>
            {(analysis.patterns||[]).map((p,i)=>(
              <div key={i} style={{color:C.t2,fontSize:12,padding:"7px 10px",background:`${C.primary}08`,borderRadius:9,marginBottom:6,lineHeight:1.5,border:`1px solid ${C.primary}15`}}>
                🔍 {p}
              </div>
            ))}
          </div>

          {/* The surprise insight */}
          <div style={{background:"linear-gradient(135deg,rgba(255,209,102,0.1),rgba(255,209,102,0.05))",border:"1px solid rgba(255,209,102,0.3)",borderRadius:16,padding:"16px",marginBottom:12}}>
            <div style={{color:"#FFD166",fontWeight:800,fontSize:13,marginBottom:8}}>💡 התובנה המפתיעה</div>
            <div style={{color:"rgba(255,255,255,0.7)",fontSize:13,lineHeight:1.7}}>{analysis.insight}</div>
          </div>
        </div>
      )}
    </div>
  );
}

function ProfileMoreTab({prof}){
  const C=useC();
  const [sub,setSub]=useState("achievements");
  const [mounted,setMounted]=useState(false);
  const savedY=useRef(null);

  useEffect(()=>{
    setMounted(false);
    const t=setTimeout(()=>setMounted(true),60);
    return()=>clearTimeout(t);
  },[sub]);

  function handleSubClick(k){
    savedY.current=window.scrollY;
    setSub(k);
  }

  const unlocked=prof.achievements.filter(a=>a.u).length;
  const total=prof.achievements.length;

  return(
    <div style={{padding:"14px 16px"}}>
      <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:14,paddingBottom:2}}>
        {[["achievements","🏅 הישגים"],["challenges","🎯 אתגרים"],["career","🏆 קריירה"],["dna","🧬 DNA"],["ai","🤖 AI"]].map(([k,l])=>(
          <button key={k} onClick={()=>handleSubClick(k)}
            style={{flexShrink:0,padding:"6px 14px",borderRadius:20,border:"none",cursor:"pointer",
              background:sub===k?C.primary:"rgba(255,255,255,0.07)",
              color:sub===k?"#000":C.t2,fontWeight:700,fontSize:11,fontFamily:"inherit"}}>
            {l}
          </button>
        ))}
      </div>

      {sub==="goals"&&<GoalsTab role="player" primaryColor={C.primary} cardBg={C.card} cardBorder={C.border} textColor={C.t1}/>}

      {sub==="capsule"&&<TimeCapsuleTab C={C}/>}

      {sub==="career"&&<CareerModeTab/>}

      {sub==="dna"&&(
        <div>
          <div style={{marginBottom:16}}><ArchetypeIdentityCard prof={prof}/></div>
          <SportsDNATab C={C}/>
        </div>
      )}

      {sub==="achievements"&&(
        <div>
          {/* Streak + Badges */}
          <div style={{marginBottom:14}}><StreakWidget streak={4}/></div>
          <div style={{marginBottom:16}}><BadgesRow earnedKeys={["early_bird","iron_man","goal_machine","reliability"]}/></div>
          {/* Progress summary with animation */}
          <div style={{background:C.card,borderRadius:17,padding:16,marginBottom:14,border:`1px solid ${C.border}`}}>
            <div style={{display:"flex",alignItems:"center",gap:16,marginBottom:12}}>
              <RadialProgress pct={mounted?(unlocked/total)*100:0} color={C.gold} size={72} stroke={7}>
                <div style={{color:C.gold,fontWeight:900,fontSize:15,lineHeight:1}}>{mounted?<AnimNumber target={unlocked} delay={100}/>:0}</div>
                <div style={{color:C.t3,fontSize:8}}>מתוך {total}</div>
              </RadialProgress>
              <div style={{flex:1}}>
                <div style={{color:C.t1,fontWeight:800,fontSize:14,marginBottom:4,direction:"rtl"}}>🏅 הישגים</div>
                <div style={{color:C.t3,fontSize:11,marginBottom:8,direction:"rtl"}}>{unlocked} הושגו מתוך {total}</div>
                <AnimBar pct={mounted?(unlocked/total)*100:0} color={`linear-gradient(90deg,${C.gold},${C.primary})`} delay={150} height={6}/>
              </div>
            </div>
          </div>
          {/* Grid with pop-in animation */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9}}>
            {prof.achievements.map((a,i)=>(
              <div key={a.title} style={{background:C.card,borderRadius:15,padding:"13px 11px",textAlign:"center",
                border:`1px solid ${a.u?C.primary+"44":"rgba(255,255,255,0.05)"}`,opacity:a.u?1:0.4,
                animation:mounted?`popIn 0.4s ease ${i*60}ms both`:"none"}}>
                <div style={{fontSize:27,marginBottom:5,filter:a.u?"none":"grayscale(1)"}}>{a.icon}</div>
                <div style={{color:a.u?"#fff":C.t2,fontWeight:700,fontSize:12}}>{a.title}</div>
                <div style={{color:C.t3,fontSize:10,marginTop:1}}>{a.desc}</div>
                {a.u&&<div style={{color:C.primary,fontSize:9,marginTop:3,fontWeight:700}}>✓ הושג</div>}
              </div>
            ))}
          </div>
        </div>
      )}

      {sub==="challenges"&&(
        <div>
          {/* Summary bar */}
          <div style={{background:C.card,borderRadius:17,padding:16,marginBottom:14,border:`1px solid ${C.border}`}}>
            <div style={{display:"flex",alignItems:"center",gap:16}}>
              <RadialProgress pct={mounted?(prof.challenges.filter(c=>c.done).length/prof.challenges.length)*100:0} color={C.accent} size={72} stroke={7}>
                <div style={{color:C.accent,fontWeight:900,fontSize:15,lineHeight:1}}>{mounted?<AnimNumber target={prof.challenges.filter(c=>c.done).length} delay={100}/>:0}</div>
                <div style={{color:C.t3,fontSize:8}}>הושלמו</div>
              </RadialProgress>
              <div style={{flex:1}}>
                <div style={{color:C.t1,fontWeight:800,fontSize:14,marginBottom:4,direction:"rtl"}}>🎯 אתגרים</div>
                <div style={{color:C.t3,fontSize:11,marginBottom:8,direction:"rtl"}}>{prof.challenges.filter(c=>c.done).length} מתוך {prof.challenges.length}</div>
                <AnimBar pct={mounted?(prof.challenges.filter(c=>c.done).length/prof.challenges.length)*100:0} color={C.accent} delay={150} height={6}/>
              </div>
            </div>
          </div>
          {/* Each challenge with animated progress bar */}
          <div style={{display:"flex",flexDirection:"column",gap:9}}>
            {prof.challenges.map((ch,i)=>(
              <div key={ch.id} style={{background:C.card,borderRadius:14,padding:"12px 14px",border:`1px solid ${ch.done?ch.color+"44":"rgba(255,255,255,0.06)"}`,
                animation:mounted?`fadeInUp 0.35s ease ${i*50}ms both`:"none",direction:"rtl"}}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:ch.done?0:8}}>
                  <span style={{fontSize:18}}>{ch.icon}</span>
                  <div style={{flex:1}}>
                    <div style={{color:ch.done?"#fff":C.t2,fontWeight:700,fontSize:12}}>{ch.title}</div>
                    <div style={{color:C.t3,fontSize:10,marginTop:1}}>{ch.category} · {ch.reward}</div>
                  </div>
                  {ch.done
                    ? <div style={{color:ch.color,fontSize:16}}>✓</div>
                    : <div style={{color:C.t3,fontSize:11,fontWeight:700}}>{ch.progress}/{ch.total}</div>
                  }
                </div>
                {!ch.done&&<AnimBar pct={mounted?(ch.progress/ch.total)*100:0} color={ch.color} delay={i*50+100} height={4}/>}
              </div>
            ))}
          </div>
        </div>
      )}

      {sub==="ai"&&<AICoachFull/>}
    </div>
  );
}

// Demo game photos (emoji placeholders with gradient backgrounds)
const GAME_PHOTOS = [
  {id:1,bg:"linear-gradient(135deg,#1a3a2a,#0d5c3a)",emoji:"⚽",label:"כדורגל 6v6 · פארק הירקון",date:"2 מרץ"},
  {id:2,bg:"linear-gradient(135deg,#1a2a3a,#0d3a5c)",emoji:"🏀",label:"כדורסל · מגרש הנמל",date:"28 פבר"},
  {id:3,bg:"linear-gradient(135deg,#3a1a2a,#5c0d3a)",emoji:"🏃",label:"ריצת בוקר 5K",date:"25 פבר"},
  {id:4,bg:"linear-gradient(135deg,#2a2a1a,#4a4a0d)",emoji:"⚽",label:"ליגה אזורית · סיבוב 3",date:"20 פבר"},
  {id:5,bg:"linear-gradient(135deg,#1a1a3a,#0d0d5c)",emoji:"🎾",label:"טניס 1v1 · טניס פארק",date:"15 פבר"},
  {id:6,bg:"linear-gradient(135deg,#3a2a1a,#5c3a0d)",emoji:"⚽",label:"כדורגל חוף · תל ברוך",date:"10 פבר"},
  {id:7,bg:"linear-gradient(135deg,#1a3a3a,#0d5c5c)",emoji:"🏐",label:"כדורעף חוף",date:"5 פבר"},
  {id:8,bg:"linear-gradient(135deg,#2a1a3a,#3a0d5c)",emoji:"🏃",label:"מרוץ 10K · פארק",date:"1 פבר"},
  {id:9,bg:"linear-gradient(135deg,#3a1a1a,#5c0d0d)",emoji:"⚽",label:"גמר עונה",date:"28 ינו"},
];

function ProfilePage(){
  const C=useC();
  const {user:prof,setUser:saveProf}=useUser();
  const [tab,setTab]=useState("photos");
  const [editOpen,setEditOpen]=useState(false);
  const [selPhoto,setSelPhoto]=useState(null);
  const [followSheet,setFollowSheet]=useState(null);
  const [teamsOpen,setTeamsOpen]=useState(false);
  const [aiCoachProfileOpen,setAiCoachProfileOpen]=useState(false);
  const [coverPhotoPicker,setCoverPhotoPicker]=useState(false);
  const [avatarPhotoPicker,setAvatarPhotoPicker]=useState(false);

  const lv=getLevel(prof.xp||0);
  const {cur,next,pct,xpToNext}=getLevelProgress(prof.xp||0);

  function switchTab(k){
    const y=window.scrollY;
    setTab(k);
    requestAnimationFrame(()=>requestAnimationFrame(()=>{ window.scrollTo({top:y,behavior:"instant"}); }));
  }

  return(
    <div style={{paddingBottom:100,direction:"rtl"}}>

      {/* ── COVER + AVATAR ── */}
      <div style={{position:"relative",marginBottom:56}}>
        {/* Cover — clickable */}
        <div onClick={()=>setCoverPhotoPicker(true)} style={{height:130,background:prof.coverPhoto?`url(${prof.coverPhoto}) center/cover`:"linear-gradient(135deg,#0a1628,#0d2444,#1a1040,#0a2820)",position:"relative",overflow:"hidden",cursor:"pointer"}}>
          {!prof.coverPhoto&&<>
            <div style={{position:"absolute",inset:0,background:"radial-gradient(ellipse at 30% 50%,rgba(0,255,179,0.15) 0%,transparent 60%)"}}/>
            <div style={{position:"absolute",inset:0,background:"radial-gradient(ellipse at 80% 30%,rgba(77,159,255,0.12) 0%,transparent 60%)"}}/>
          </>}
          <div style={{position:"absolute",bottom:8,left:16,display:"flex",gap:6}}>
            {(prof.sports||[]).slice(0,3).map((s,i)=>(
              <div key={i} style={{background:"rgba(255,255,255,0.1)",borderRadius:8,padding:"3px 8px",color:"rgba(255,255,255,0.6)",fontSize:10,fontWeight:600,backdropFilter:"blur(8px)"}}>{s==="football"?"⚽":s==="basketball"?"🏀":s==="running"?"🏃":s==="tennis"?"🎾":"🏅"}</div>
            ))}
          </div>
          <div style={{position:"absolute",top:8,right:8,background:"rgba(0,0,0,0.45)",borderRadius:8,padding:"4px 8px",display:"flex",alignItems:"center",gap:4,backdropFilter:"blur(8px)"}}>
            <span style={{fontSize:10,color:"rgba(255,255,255,0.8)"}}>📷 שנה רקע</span>
          </div>
        </div>

        {/* Avatar — clickable, overlaps cover */}
        <div style={{position:"absolute",bottom:-44,right:16,zIndex:2}}>
          <div style={{position:"relative",cursor:"pointer"}} onClick={()=>setAvatarPhotoPicker(true)}>
            {prof.photo
              ? <img src={prof.photo} style={{width:86,height:86,borderRadius:"50%",objectFit:"cover",border:`3px solid ${C.dark}`}}/>
              : <div style={{width:86,height:86,borderRadius:"50%",background:"linear-gradient(135deg,#3B5BDB,#7B8DE8)",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:800,fontSize:28,border:`3px solid ${C.dark}`}}>{prof.initials}</div>
            }
            <div style={{position:"absolute",bottom:2,left:2,width:26,height:26,borderRadius:"50%",background:cur.color,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,border:`2px solid ${C.dark}`}}>{cur.icon}</div>
            <div style={{position:"absolute",top:0,right:0,width:24,height:24,borderRadius:"50%",background:"rgba(0,0,0,0.65)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,border:`2px solid ${C.dark}`}}>📷</div>
          </div>
        </div>

        {/* Edit + share buttons top-left */}
        <div style={{position:"absolute",bottom:-38,left:16,display:"flex",gap:8}}>
          <button onClick={()=>setEditOpen(true)}
            style={{padding:"8px 16px",borderRadius:20,border:`1.5px solid ${C.primary}`,background:"transparent",color:C.primary,fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
            ✏️ ערוך פרופיל
          </button>
          <button style={{width:34,height:34,borderRadius:"50%",border:`1.5px solid ${C.border}`,background:"transparent",color:C.t2,cursor:"pointer",fontFamily:"inherit",fontSize:14}}>
            📤
          </button>
        </div>
      </div>

      {/* ── BIO SECTION — Instagram style ── */}
      <div style={{padding:"0 16px 14px",borderBottom:`1px solid ${C.border}`}}>

        {/* Row 1: stats next to avatar (Instagram layout) */}
        <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:14,marginTop:4}}>
          {/* Spacer matching avatar width */}
          <div style={{width:86+16}}/>
          {/* Stats: משחקים · עוקבים · עוקב */}
          {[
            {v:prof.events||11,         l:"פוסטים",  click:null},
            {v:FOLLOWERS_DATA.length,   l:"עוקבים",  click:()=>setFollowSheet("followers")},
            {v:FOLLOWING_DATA.length,   l:"עוקב",    click:()=>setFollowSheet("following")},
          ].map(({v,l,click},i)=>(
            <div key={l} onClick={click||undefined}
              style={{flex:1,textAlign:"center",cursor:click?"pointer":"default"}}>
              <div style={{color:C.t1,fontWeight:800,fontSize:17,lineHeight:1}}>{v}</div>
              <div style={{color:C.t3,fontSize:11,marginTop:3}}>{l}</div>
            </div>
          ))}
        </div>

        {/* Row 2: name + level badge */}
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:2}}>
          <div style={{color:C.t1,fontWeight:900,fontSize:17}}>{prof.name}</div>
          <div style={{color:C.primary,fontSize:10,fontWeight:700,background:`${C.primary}15`,padding:"2px 8px",borderRadius:6}}>{lv.name}</div>
        </div>

        {/* Row 3: username */}
        {prof.username&&<div style={{color:C.t3,fontSize:12,marginBottom:4}}>@{prof.username}</div>}

        {/* Row 4: bio */}
        {prof.bio&&<div style={{color:C.t2,fontSize:13,lineHeight:1.6,marginBottom:6}}>{prof.bio}</div>}

        {/* Row 5: instagram link */}
        {prof.instagram&&(
          <div style={{display:"inline-flex",alignItems:"center",gap:5}}>
            <span style={{fontSize:12}}>📸</span>
            <span style={{color:C.blue,fontSize:12,fontWeight:600}}>@{prof.instagram}</span>
          </div>
        )}
      </div>

      {/* ── XP BAR ── */}
      <div style={{padding:"10px 16px",borderBottom:`1px solid ${C.border}`}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <span style={{fontSize:14}}>{cur.icon}</span>
            <span style={{color:cur.color,fontWeight:700,fontSize:12}}>{cur.name}</span>
            {next&&<span style={{color:C.t3,fontSize:10}}>→ {next.name}</span>}
          </div>
          <span style={{color:C.t3,fontSize:10}}>{(prof.xp||0).toLocaleString()} XP {next&&`· עוד ${xpToNext.toLocaleString()}`}</span>
        </div>
        <div style={{height:4,background:"rgba(255,255,255,0.07)",borderRadius:2}}>
          <div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${cur.color},${next?next.color:cur.color})`,borderRadius:2,transition:"width 0.5s"}}/>
        </div>
      </div>

      {/* ── ARCHETYPE IDENTITY STRIP ── */}
      <div style={{padding:"10px 16px",borderBottom:`1px solid ${C.border}`}}>
        <div style={{display:"flex",gap:10,alignItems:"center",justifyContent:"space-between"}}>
          <ArchetypeIdentityCard prof={prof} compact={true}/>
          <div style={{display:"flex",gap:6}}>
            <button onClick={()=>setAiCoachProfileOpen(true)}
              style={{padding:"7px 12px",borderRadius:14,border:"1px solid rgba(0,255,179,0.25)",
                background:"rgba(0,255,179,0.06)",color:"#00FFB3",fontSize:10,fontWeight:700,
                cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>
              🤖 AI Coach
            </button>
            <button onClick={()=>setTeamsOpen(true)}
              style={{padding:"7px 12px",borderRadius:14,border:"1px solid rgba(255,209,102,0.25)",
                background:"rgba(255,209,102,0.06)",color:"#FFD166",fontSize:10,fontWeight:700,
                cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>
              ⚽ קבוצות
            </button>
          </div>
        </div>
      </div>

      {/* ── TABS ── */}
      <div style={{display:"flex",borderBottom:`1px solid ${C.border}`,position:"sticky",top:54,background:C.dark,zIndex:10,overflowX:"auto"}}>
        {[["photos","📸"],["stats","📊"],["history","📜"],["card","🎮"],["chemistry","🔗"],["more","🏅"]].map(([k,l])=>(
          <button key={k} onClick={()=>switchTab(k)}
            style={{flexShrink:0,padding:"10px 12px",border:"none",background:"transparent",cursor:"pointer",
              fontWeight:700,fontSize:13,fontFamily:"inherit",
              color:tab===k?C.primary:C.t2,
              borderBottom:tab===k?`2px solid ${C.primary}`:"2px solid transparent",
              transition:"all 0.2s"}}>
            {l}
          </button>
        ))}
      </div>

      {/* ── PHOTOS GRID ── */}
      {tab==="photos"&&(
        <div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:2,padding:"2px"}}>
            {GAME_PHOTOS.map((p,i)=>(
              <div key={p.id} onClick={()=>setSelPhoto(p)}
                style={{aspectRatio:"1",background:p.bg,cursor:"pointer",position:"relative",
                  gridColumn:i===0?"span 2":"span 1",
                  gridRow:i===0?"span 2":"span 1",
                  overflow:"hidden"}}>
                <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:i===0?52:28}}>{p.emoji}</div>
                <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"6px 8px",background:"linear-gradient(transparent,rgba(0,0,0,0.7))"}}>
                  <div style={{color:"#fff",fontSize:i===0?11:9,fontWeight:600}}>{p.date}</div>
                </div>
              </div>
            ))}
          </div>
          {GAME_PHOTOS.length===0&&(
            <div style={{textAlign:"center",padding:"50px 16px",color:C.t3}}>
              <div style={{fontSize:44,marginBottom:12}}>📸</div>
              <div style={{fontSize:14,fontWeight:700}}>עדיין אין תמונות</div>
              <div style={{fontSize:12,marginTop:6}}>תמונות ממשחקים יופיעו כאן</div>
            </div>
          )}
        </div>
      )}

      {/* ── STATS ── */}
      {tab==="stats"&&<ProfileStatsTab prof={prof}/>}

      {tab==="more"&&<ProfileMoreTab prof={prof}/>}

      {/* ── HISTORY ── */}
      {tab==="history"&&(
        <div style={{padding:"14px 16px"}}>
          <GameHistoryTab/>
        </div>
      )}

      {/* ── PLAYER CARD ── */}
      {tab==="card"&&(
        <div style={{padding:"20px 16px"}}>
          <FIFAPlayerCard prof={prof}/>
          <div style={{marginTop:16}}>
            <PlayStyleSelector value={prof?.playStyle||"team"} onChange={()=>{}}/>
          </div>
        </div>
      )}

      {/* ── CHEMISTRY ── */}
      {tab==="chemistry"&&(
        <div style={{padding:"14px 16px"}}>
          <ChemistryTab/>
        </div>
      )}

      {/* ── TEAMS / RIVALRIES / CAREER modal sheets ── */}
      <Sheet open={teamsOpen} onClose={()=>setTeamsOpen(false)} title="⚽ קבוצות ויריבויות" h="90vh">
        <div style={{padding:"4px 0"}}>
          <TeamsRivalriesSheet onClose={()=>setTeamsOpen(false)}/>
          <div style={{marginTop:20,borderTop:"1px solid rgba(255,255,255,0.07)",paddingTop:16}}>
            <CareerModeTab/>
          </div>
        </div>
      </Sheet>
      <Sheet open={aiCoachProfileOpen} onClose={()=>setAiCoachProfileOpen(false)} title="🤖 AI Coach" h="92vh">
        <AICoachFull onClose={()=>setAiCoachProfileOpen(false)}/>
      </Sheet>

      {/* ── PHOTO LIGHTBOX ── */}
      {selPhoto&&(
        <div onClick={()=>setSelPhoto(null)} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.9)",zIndex:999,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
          <div style={{width:"90%",maxWidth:360,aspectRatio:"1",background:selPhoto.bg,borderRadius:18,display:"flex",alignItems:"center",justifyContent:"center",fontSize:72,marginBottom:14}}>
            {selPhoto.emoji}
          </div>
          <div style={{color:"#fff",fontWeight:700,fontSize:14,marginBottom:4}}>{selPhoto.label}</div>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:12}}>{selPhoto.date}</div>
        </div>
      )}

      <Sheet open={editOpen} onClose={()=>setEditOpen(false)} title="עריכת פרופיל" h="92vh">
        <ProfileEditForm onClose={()=>setEditOpen(false)}/>
      </Sheet>
      <Sheet open={!!followSheet} onClose={()=>setFollowSheet(null)}
        title={followSheet==="followers"?`עוקבים (${FOLLOWERS_DATA.length})`:`עוקב (${FOLLOWING_DATA.length})`} h="80vh">
        <FollowListSheet type={followSheet} onClose={()=>setFollowSheet(null)}/>
      </Sheet>
      <PhotoPickerSheet open={coverPhotoPicker} onClose={()=>setCoverPhotoPicker(false)} onPhoto={src=>saveProf(u=>({...u,coverPhoto:src}))}/>
      <PhotoPickerSheet open={avatarPhotoPicker} onClose={()=>setAvatarPhotoPicker(false)} onPhoto={src=>saveProf(u=>({...u,photo:src}))}/>
    </div>
  );
}

