/* ─── SETTINGS ACCOUNT SUB-PAGE  -  standalone component to avoid TF-inside-component bug ─── */
/* ─── MODULE-SCOPE input helpers  -  MUST be outside any component to prevent focus loss ─── */
const SI_STYLE={background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.08)",color:"#fff",fontSize:14,direction:"rtl",outline:"none",boxSizing:"border-box",fontFamily:"inherit",borderRadius:14,padding:"13px 15px",width:"100%",transition:"border-color 0.2s"};
function handleFocus(e){e.target.style.borderColor="rgba(0,192,127,0.4)";}
function handleBlur(e){e.target.style.borderColor="rgba(255,255,255,0.08)";}
function FieldLabel({t}){return <div style={{color:"rgba(255,255,255,0.38)",fontSize:10,fontWeight:700,letterSpacing:"0.09em",textTransform:"uppercase",marginBottom:6,direction:"rtl"}}>{t}</div>;}

function AccountSettings({onBack,onPwOpen,onDeleteOpen}){
  const C=useC();
  const {user,setUser}=useUser();
  const [photoPicker,setPhotoPicker]=useState(false);
  const [photo,setPhoto]=useState(user.photo||null);
  const [name,setName]=useState(user.name||"");
  const [username,setUsername]=useState(user.username||"asaf_plays");
  const [email,setEmail]=useState(user.email||"asaf@gmail.com");
  const [phone,setPhone]=useState(user.phone||"+972-50-123-4567");
  const [bio,setBio]=useState(user.bio||"");
  const [instagram,setInstagram]=useState(user.instagram||"");
  const [facebook,setFacebook]=useState(user.facebook||"");
  const [twitter,setTwitter]=useState(user.twitter||"");
  const [twoFactor,setTwoFactor]=useState(false);
  const [saved,setSaved]=useState(false);

  function save(){
    const initials=(name||"XX").split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase();
    setUser(u=>({...u,name,username,email,phone,bio,instagram,facebook,twitter,photo,initials}));
    setSaved(true);
    setTimeout(()=>{setSaved(false);onBack();},1000);
  }

  // NOTE: SI, onFocus, onBlur, LBL are defined outside this component (module scope) to prevent remount

  return(
    <div style={{direction:"rtl"}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:22}}>
        <button onClick={onBack} style={{width:34,height:34,borderRadius:10,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.08)",cursor:"pointer",color:"rgba(255,255,255,0.6)",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>←</button>
        <span style={{color:"#fff",fontWeight:700,fontSize:16}}>חשבון ופרופיל</span>
      </div>
      {/* Photo */}
      <div style={{display:"flex",alignItems:"center",gap:16,padding:"16px",background:"rgba(255,255,255,0.03)",borderRadius:18,border:"1px solid rgba(255,255,255,0.06)",marginBottom:20}}>
        <div style={{position:"relative",cursor:"pointer",flexShrink:0}} onClick={()=>setPhotoPicker(true)}>
          <div style={{width:72,height:72,borderRadius:"50%",background:"linear-gradient(135deg,#1a1f3a,#2d3561)",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:800,fontSize:22,border:"2px solid rgba(0,192,127,0.3)",overflow:"hidden"}}>
            {photo?<img src={photo} style={{width:"100%",height:"100%",objectFit:"cover"}}/>:(user.initials||"AS")}
          </div>
          <div style={{position:"absolute",bottom:0,right:0,width:22,height:22,borderRadius:"50%",background:"#00C07F",border:"2px solid #0F1A2B",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
          </div>
        </div>
        <div>
          <div style={{color:"#fff",fontWeight:700,fontSize:15}}>{name||user.name}</div>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:12,marginTop:2}}>@{username||"asaf_plays"}</div>
          <button onClick={()=>setPhotoPicker(true)} style={{marginTop:6,padding:"4px 10px",borderRadius:8,background:"rgba(0,192,127,0.1)",border:"1px solid rgba(0,192,127,0.2)",color:"rgba(0,192,127,0.9)",fontSize:11,cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>שנה תמונה</button>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
        <div><FieldLabel t="שם מלא"/><input value={name} onChange={e=>setName(e.target.value)} placeholder="השם שלך" style={SI_STYLE} onFocus={handleFocus} onBlur={handleBlur}/></div>
        <div><FieldLabel t="שם משתמש"/><input value={username} onChange={e=>setUsername(e.target.value)} placeholder="@username" style={SI_STYLE} onFocus={handleFocus} onBlur={handleBlur}/></div>
      </div>
      <div style={{marginBottom:10}}><FieldLabel t="אימייל"/><input value={email} onChange={e=>setEmail(e.target.value)} type="email" placeholder="email@example.com" style={SI_STYLE} onFocus={handleFocus} onBlur={handleBlur}/></div>
      <div style={{marginBottom:10}}><FieldLabel t="טלפון"/><input value={phone} onChange={e=>setPhone(e.target.value)} type="tel" placeholder="+972-5x-xxx-xxxx" style={SI_STYLE} onFocus={handleFocus} onBlur={handleBlur}/></div>
      <div style={{marginBottom:16}}><FieldLabel t="ביוגרפיה"/><textarea value={bio} onChange={e=>setBio(e.target.value)} placeholder="ספר על עצמך..." rows={2} style={{...SI_STYLE,resize:"none",lineHeight:1.5}}/></div>
      {/* Social */}
      <div style={{marginBottom:16}}>
        <FieldLabel t="רשתות חברתיות"/>
        {[["Instagram",instagram,setInstagram,"https://instagram.com/"],["Facebook",facebook,setFacebook,"https://facebook.com/"],["Twitter/X",twitter,setTwitter,"https://twitter.com/"]].map(([nm,val,fn,base])=>(
          <div key={nm} style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
            <div style={{width:36,height:36,borderRadius:10,background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.07)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,color:"rgba(255,255,255,0.4)",fontSize:11,fontWeight:700}}>{nm[0]}</div>
            <input value={val} onChange={e=>fn(e.target.value)} placeholder={`@${nm.toLowerCase().replace("/x","")}`}
              style={{...SI_STYLE,flex:1,width:"auto",borderRadius:12,padding:"10px 13px"}} onFocus={handleFocus} onBlur={handleBlur}/>
            {val&&<a href={`${base}${val.replace("@","")}`} target="_blank" rel="noreferrer"
              style={{width:36,height:36,borderRadius:10,background:"rgba(0,119,204,0.08)",border:"1px solid rgba(0,119,204,0.2)",display:"flex",alignItems:"center",justifyContent:"center",textDecoration:"none",flexShrink:0}}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="rgba(96,175,255,0.7)" strokeWidth="2"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>
            </a>}
          </div>
        ))}
      </div>
      {/* Security */}
      <div style={{background:"rgba(255,255,255,0.03)",borderRadius:16,border:"1px solid rgba(255,255,255,0.06)",overflow:"hidden",marginBottom:16}}>
        {[
          {label:"שינוי סיסמה",desc:"דרוש אימות סיסמה נוכחית",action:onPwOpen},
          {label:"אימות דו-שלבי",desc:twoFactor?"פעיל  -  SMS":"לא פעיל",right:<div onClick={()=>setTwoFactor(v=>!v)} style={{width:42,height:24,borderRadius:12,background:twoFactor?"#00C07F":"rgba(255,255,255,0.1)",cursor:"pointer",position:"relative",transition:"background 0.2s",flexShrink:0}}><div style={{position:"absolute",top:2,left:twoFactor?19:2,width:20,height:20,borderRadius:"50%",background:"#fff",transition:"left 0.2s"}}/></div>},
          {label:"מחיקת חשבון",desc:"פעולה בלתי הפיכה",action:onDeleteOpen,danger:true},
        ].map((row,i,arr)=>(
          <div key={row.label} onClick={row.action} style={{display:"flex",alignItems:"center",gap:12,padding:"14px 16px",borderBottom:i<arr.length-1?"1px solid rgba(255,255,255,0.05)":"none",cursor:row.action?"pointer":"default",direction:"rtl"}}>
            <div style={{flex:1}}>
              <div style={{color:row.danger?"rgba(255,71,87,0.9)":"#fff",fontSize:13,fontWeight:600}}>{row.label}</div>
              {row.desc&&<div style={{color:"rgba(255,255,255,0.35)",fontSize:11,marginTop:1}}>{row.desc}</div>}
            </div>
            {row.right||<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="2"><polyline points="15 18 9 12 15 6"/></svg>}
          </div>
        ))}
      </div>
      <button onClick={save} style={{width:"100%",padding:"15px",borderRadius:14,border:`1px solid ${saved?"rgba(0,192,127,0.4)":"rgba(0,192,127,0.2)"}`,cursor:"pointer",background:saved?"rgba(0,192,127,0.12)":"rgba(0,192,127,0.08)",color:"rgba(0,192,127,0.95)",fontWeight:700,fontSize:14,fontFamily:"inherit",transition:"all 0.3s",letterSpacing:"0.02em"}}>
        {saved?"✓ נשמר בהצלחה":"שמור שינויים"}
      </button>
      <PhotoPickerSheet open={photoPicker} onClose={()=>setPhotoPicker(false)} onPhoto={src=>setPhoto(src)}/>
    </div>
  );
}

