const WATCH_TYPES = [
  {id:"apple",    name:"Apple Watch",     icon:"⌚", color:"#A0A0A0", desc:"Series 4+, watchOS 7+"},
  {id:"garmin",   name:"Garmin",          icon:"🟢", color:"#00A651", desc:"Forerunner, Fenix, Venu"},
  {id:"samsung",  name:"Samsung Galaxy",  icon:"💙", color:"#1428A0", desc:"Galaxy Watch 4+"},
  {id:"fitbit",   name:"Fitbit",          icon:"🔵", color:"#00B0B9", desc:"Sense, Versa, Charge 5"},
  {id:"polar",    name:"Polar",           icon:"🔴", color:"#D0021B", desc:"Vantage, Ignite, Pacer"},
  {id:"suunto",   name:"Suunto",          icon:"⚫", color:"#FF6600", desc:"9, Race, Vertical"},
];

const WATCH_METRICS_LABELS = {
  heartRate: {label:"קצב לב", icon:"❤️", desc:"בזמן אמת במהלך פעילות"},
  steps:     {label:"צעדים", icon:"👟", desc:"מונה צעדים יומי"},
  calories:  {label:"קלוריות", icon:"🔥", desc:"שריפת קלוריות"},
  distance:  {label:"מרחק", icon:"📍", desc:"GPS מהשעון"},
  sleep:     {label:"שינה", icon:"😴", desc:"ניתוח שינה לילי"},
  stress:    {label:"מתח", icon:"🧘", desc:"מדד מתח ו-HRV"},
};

const BT_DEVICES_MOCK = [
  {id:"bt1", name:"Apple Watch Series 9", type:"apple", rssi:-58, paired:true},
  {id:"bt2", name:"AirPods Pro", type:"headphones", rssi:-72, paired:false},
  {id:"bt3", name:"Garmin Forerunner 255", type:"garmin", rssi:-65, paired:false},
];

function SmartWatchSection({settings, S}){
  const C = useC();
  const [tab, setTab] = useState("watch");
  const [btStatus, setBtStatus] = useState("idle"); // idle | requesting | connecting | connected | error | unsupported
  const [btError, setBtError] = useState("");
  const [liveData, setLiveData] = useState({heartRate:null,steps:null,calories:null,battery:null});
  const hrIntervalRef = useRef(null);
  const deviceRef = useRef(null);

  // Check Web Bluetooth support
  const btSupported = typeof navigator !== "undefined" && !!navigator.bluetooth;

  useEffect(()=>{
    return ()=>{
      // Cleanup on unmount
      if(hrIntervalRef.current) clearInterval(hrIntervalRef.current);
      if(deviceRef.current && deviceRef.current.gatt && deviceRef.current.gatt.connected){
        deviceRef.current.gatt.disconnect();
      }
    };
  },[]);

  async function connectRealBluetooth(){
    if(!btSupported){
      setBtStatus("unsupported");
      return;
    }
    setBtStatus("requesting");
    setBtError("");
    try {
      // Request any device that supports Heart Rate or Generic Access service
      // This opens the REAL browser BT picker showing nearby devices
      const device = await navigator.bluetooth.requestDevice({
        acceptAllDevices: false,
        filters: [
          { services: ["heart_rate"] },
          { services: ["fitness_machine"] },
          { namePrefix: "Apple Watch" },
          { namePrefix: "Garmin" },
          { namePrefix: "Samsung" },
          { namePrefix: "Polar" },
          { namePrefix: "Fitbit" },
          { namePrefix: "Suunto" },
          { namePrefix: "Mi" },
        ],
        optionalServices: ["heart_rate","battery_service","fitness_machine","generic_access"]
      });

      setBtStatus("connecting");
      deviceRef.current = device;

      device.addEventListener("gattserverdisconnected", ()=>{
        setBtStatus("idle");
        S("watchConnected", false);
        S("btDevice", null);
        setLiveData({heartRate:null,steps:null,calories:null,battery:null});
        if(hrIntervalRef.current) clearInterval(hrIntervalRef.current);
      });

      const server = await device.gatt.connect();

      // Detect device name and type
      const devName = device.name || "שעון חכם";
      const watchIcon = devName.includes("Apple")?"⌚":devName.includes("Garmin")?"🟢":devName.includes("Samsung")?"💙":devName.includes("Polar")?"🔴":devName.includes("Fitbit")?"🔵":"⌚";

      S("watchConnected", true);
      S("watchType", devName);
      S("btDevice", {id:device.id, name:devName, icon:watchIcon});
      S("btEnabled", true);
      setBtStatus("connected");

      // Try to read Heart Rate
      try {
        const hrService = await server.getPrimaryService("heart_rate");
        const hrChar = await hrService.getCharacteristic("heart_rate_measurement");
        await hrChar.startNotifications();
        hrChar.addEventListener("characteristicvaluechanged", (e)=>{
          const val = e.target.value;
          const flags = val.getUint8(0);
          const hr = flags & 0x1 ? val.getUint16(1, true) : val.getUint8(1);
          setLiveData(d=>({...d, heartRate:hr}));
        });
      } catch(e){ /* device may not have HR service */ }

      // Try to read Battery
      try {
        const batService = await server.getPrimaryService("battery_service");
        const batChar = await batService.getCharacteristic("battery_level");
        const batVal = await batChar.readValue();
        setLiveData(d=>({...d, battery:batVal.getUint8(0)}));
      } catch(e){ /* no battery service */ }

    } catch(err){
      if(err.name === "NotFoundError" || err.name === "AbortError"){
        // User cancelled picker
        setBtStatus("idle");
      } else {
        setBtStatus("error");
        setBtError(err.message || "שגיאת בלוטות'");
      }
    }
  }

  function disconnect(){
    if(deviceRef.current && deviceRef.current.gatt && deviceRef.current.gatt.connected){
      deviceRef.current.gatt.disconnect();
    }
    if(hrIntervalRef.current) clearInterval(hrIntervalRef.current);
    deviceRef.current = null;
    setBtStatus("idle");
    S("watchConnected", false);
    S("btDevice", null);
    S("watchType", null);
    setLiveData({heartRate:null,steps:null,calories:null,battery:null});
  }

  const statusColor = {
    idle:"rgba(255,255,255,0.2)", requesting:C.gold, connecting:C.blue,
    connected:"#00C07F", error:C.accent, unsupported:C.accent
  }[btStatus];

  const statusLabel = {
    idle:"לא מחובר", requesting:"מחפש התקנים...", connecting:"מתחבר...",
    connected:`מחובר · ${settings.watchType||"שעון"}`,
    error:"שגיאת חיבור", unsupported:"לא נתמך בדפדפן זה"
  }[btStatus];

  return(
    <div style={{direction:"rtl"}}>

      {/* Main connect card */}
      <div style={{background:C.surface, borderRadius:20, padding:"20px",
        border:`1.5px solid ${statusColor}44`, marginBottom:14,
        background:btStatus==="connected"?"rgba(0,192,127,0.06)":"rgba(255,255,255,0.03)"}}>

        <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:16}}>
          <div style={{width:56,height:56,borderRadius:16,
            background:`${statusColor}18`,
            display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,
            border:`2px solid ${statusColor}44`}}>
            {btStatus==="connected"?(settings.btDevice?.icon||"⌚"):
             btStatus==="requesting"||btStatus==="connecting"?"🔍":"📵"}
          </div>
          <div style={{flex:1}}>
            <div style={{color:C.t1,fontWeight:800,fontSize:15}}>{statusLabel}</div>
            <div style={{color:statusColor,fontSize:12,marginTop:2,fontWeight:600}}>
              {btStatus==="connected"?"🔵 בלוטות' · פעיל":
               btStatus==="requesting"?"ממתין לבחירת התקן מהרשימה...":
               btStatus==="connecting"?"מתחבר ל-GATT server...":
               btStatus==="unsupported"?"נדרש Chrome על אנדרואיד":
               btStatus==="error"?btError:
               "חפש ובחר שעון חכם"}
            </div>
            {liveData.battery!==null&&(
              <div style={{color:C.t3,fontSize:11,marginTop:1}}>
                🔋 {liveData.battery}%
              </div>
            )}
          </div>
          {btStatus==="connected"&&(
            <button onClick={disconnect}
              style={{background:"none",border:`1px solid ${C.accent}44`,borderRadius:10,
                padding:"6px 12px",cursor:"pointer",color:C.accent,
                fontSize:12,fontWeight:700,fontFamily:"inherit"}}>
              נתק
            </button>
          )}
        </div>

        {/* Connect / retry button */}
        {btStatus!=="connected"&&(
          <>
            {btStatus==="unsupported"?(
              <div style={{background:"rgba(255,71,87,0.08)",borderRadius:13,padding:"12px 14px",
                border:"1px solid rgba(255,71,87,0.2)",fontSize:12,color:C.t2,lineHeight:1.7}}>
                ⚠️ <strong style={{color:C.accent}}>Web Bluetooth</strong> לא נתמך בדפדפן זה.<br/>
                נדרש: <strong>Chrome</strong> על <strong>אנדרואיד</strong>.<br/>
                Safari/Firefox/iPhone  -  לא תומכים בחיבור בלוטות' מדפדפן.
              </div>
            ):(
              <button
                onClick={connectRealBluetooth}
                disabled={btStatus==="requesting"||btStatus==="connecting"}
                style={{width:"100%",padding:"14px",borderRadius:14,border:"none",cursor:"pointer",
                  background:btStatus==="requesting"||btStatus==="connecting"
                    ?"rgba(255,255,255,0.06)"
                    :`linear-gradient(135deg,${C.primary},${C.blue})`,
                  color:btStatus==="requesting"||btStatus==="connecting"?C.t2:"#000",
                  fontWeight:800,fontSize:15,fontFamily:"inherit",
                  display:"flex",alignItems:"center",justifyContent:"center",gap:10}}>
                {btStatus==="requesting"||btStatus==="connecting"?(
                  <><span style={{fontSize:18}}>🔍</span>
                  <span>{btStatus==="requesting"?"מחפש התקנים...":"מתחבר..."}</span></>
                ):(
                  <><span style={{fontSize:18}}>📡</span>
                  <span>{btStatus==="error"?"נסה שוב":"חפש שעון חכם"}</span></>
                )}
              </button>
            )}

            {/* Info box */}
            {btStatus==="idle"&&btSupported&&(
              <div style={{marginTop:10,background:"rgba(0,119,204,0.08)",borderRadius:12,
                padding:"10px 12px",border:"1px solid rgba(0,119,204,0.2)",
                fontSize:11,color:C.t2,lineHeight:1.7}}>
                💡 יפתח חלון בחירת התקן של הדפדפן עם כל השעונים החכמים הקרובים.
                בחר את השעון שלך מהרשימה  -  אין צורך להזין קוד.
              </div>
            )}
          </>
        )}
      </div>

      {/* Live data  -  only when connected */}
      {btStatus==="connected"&&(
        <>
          <div style={{color:C.t1,fontWeight:800,fontSize:14,marginBottom:8}}>📊 נתונים חיים</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,marginBottom:14}}>
            <div style={{background:"rgba(255,71,87,0.08)",borderRadius:16,padding:"14px",
              textAlign:"center",border:"1px solid rgba(255,71,87,0.2)"}}>
              <div style={{fontSize:22}}>❤️</div>
              <div style={{color:"#FF4757",fontWeight:900,fontSize:28,lineHeight:1,marginTop:4}}>
                {liveData.heartRate||"--"}
              </div>
              <div style={{color:C.t3,fontSize:10,marginTop:2}}>bpm</div>
              {!liveData.heartRate&&<div style={{color:C.t3,fontSize:9,marginTop:2}}>ממתין לנתון...</div>}
            </div>
            <div style={{background:"rgba(0,192,127,0.08)",borderRadius:16,padding:"14px",
              textAlign:"center",border:"1px solid rgba(0,192,127,0.2)"}}>
              <div style={{fontSize:22}}>👟</div>
              <div style={{color:"#00C07F",fontWeight:900,fontSize:28,lineHeight:1,marginTop:4}}>
                {liveData.steps||"--"}
              </div>
              <div style={{color:C.t3,fontSize:10,marginTop:2}}>צעדים</div>
            </div>
          </div>

          {/* Metrics toggles */}
          <div style={{color:C.t1,fontWeight:700,fontSize:13,marginBottom:8}}>מדדים לסנכרון</div>
          <div style={{background:C.surface,borderRadius:14,border:`1px solid ${C.border}`,overflow:"hidden"}}>
            {Object.entries({heartRate:"❤️ קצב לב",steps:"👟 צעדים",calories:"🔥 קלוריות",distance:"📍 מרחק GPS",sleep:"😴 שינה",stress:"🧘 מתח"}).map(([key,label],i,arr)=>{
              const isOn = settings.watchMetrics?.[key]??true;
              return(
                <div key={key} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",
                  borderBottom:i<arr.length-1?`1px solid ${C.border}`:"none"}}>
                  <span style={{fontSize:16,minWidth:24}}>{label.split(" ")[0]}</span>
                  <span style={{color:C.t1,fontSize:13,flex:1}}>{label.split(" ").slice(1).join(" ")}</span>
                  <button onClick={()=>S("watchMetrics",{...settings.watchMetrics,[key]:!isOn})}
                    style={{width:44,height:26,borderRadius:13,border:"none",cursor:"pointer",
                      background:isOn?C.primary:"rgba(255,255,255,0.1)",
                      position:"relative",transition:"background 0.2s",flexShrink:0}}>
                    <div style={{position:"absolute",top:2,left:isOn?20:2,width:22,height:22,
                      borderRadius:"50%",background:"#fff",transition:"left 0.2s",
                      boxShadow:"0 1px 3px rgba(0,0,0,0.3)"}}/>
                  </button>
                </div>
              );
            })}
          </div>
        </>
      )}

      {/* Compatibility note */}
      <div style={{marginTop:12,background:"rgba(255,255,255,0.03)",borderRadius:12,
        padding:"10px 13px",border:`1px solid ${C.border}`}}>
        <div style={{color:C.t3,fontSize:10,lineHeight:1.8}}>
          <strong style={{color:C.t2}}>תאימות:</strong><br/>
          ✅ Chrome על אנדרואיד  -  תמיכה מלאה<br/>
          ✅ Apple Watch, Garmin, Samsung, Polar, Fitbit, Suunto<br/>
          ❌ Safari / Firefox / iPhone  -  לא תומכים ב-Web Bluetooth
        </div>
      </div>
    </div>
  );
}

function SettingsPage(){
  const C=useC();
  const {user}=useUser();
  const [section,setSection]=useState(null);
  const [pwOpen,setPwOpen]=useState(false);
  const [deleteOpen,setDeleteOpen]=useState(false);
  const [settings,setSettings]=useState({locationPerm:"ask",notifications:true,pushGames:true,pushMessages:true,pushReminders:true,darkMode:true,language:"he",units:"km",privacy:"friends",showElo:true,showStats:true,showActivity:true,cameraAccess:"ask",twoFactor:false,activityTracking:true,heartRate:false,autoRecord:false,btEnabled:false,btDevice:null,watchConnected:false,watchType:null,watchSync:"realtime",watchMetrics:{heartRate:true,steps:true,calories:true,distance:true,sleep:false,stress:false}});
  const S=(k,v)=>setSettings(p=>({...p,[k]:v}));

  // Render AccountSettings as its own component  -  avoids any TF-inside issues
  if(section==="account")return(
    <>
      <AccountSettings onBack={()=>setSection(null)} onPwOpen={()=>setPwOpen(true)} onDeleteOpen={()=>setDeleteOpen(true)}/>
      <Sheet open={pwOpen} onClose={()=>setPwOpen(false)} title="שינוי סיסמה" h="72vh"><ChangePasswordForm onClose={()=>setPwOpen(false)}/></Sheet>
      <Sheet open={deleteOpen} onClose={()=>setDeleteOpen(false)} title="מחיקת חשבון" h="88vh"><DeleteAccountFlow onClose={()=>setDeleteOpen(false)}/></Sheet>
    </>
  );


  const secContent={
    privacy:<PrivacySection settings={settings} S={S}/>,
    notifications:<div>
      <Row label="כל ההתראות" right={<Toggle val={settings.notifications} onChange={v=>S("notifications",v)}/>}/>
      <div style={{opacity:settings.notifications?1:0.4,transition:"opacity 0.2s"}}>
        <Row label="משחקים חדשים" right={<Toggle val={settings.pushGames} onChange={v=>S("pushGames",v)}/>}/>
        <Row label="הודעות חדשות" right={<Toggle val={settings.pushMessages} onChange={v=>S("pushMessages",v)}/>}/>
        <Row label="תזכורות למשחק" desc="2 שעות לפני" right={<Toggle val={settings.pushReminders} onChange={v=>S("pushReminders",v)}/>}/>
        <Row label="בקשות חברות" right={<Toggle val={true} onChange={()=>{}}/>} border={false}/>
      </div>
    </div>,
    location:<div>
      <div style={{background:"rgba(0,214,143,0.06)",borderRadius:12,padding:"11px 13px",marginBottom:12,direction:"rtl",border:"1px solid rgba(0,214,143,0.12)"}}><div style={{color:"rgba(0,214,143,0.9)",fontWeight:600,fontSize:12,marginBottom:3}}>הרשאות מיקום</div><div style={{color:"rgba(255,255,255,0.4)",fontSize:11,lineHeight:1.6}}>המיקום משמש למציאת מגרשים ואירועים קרובים.</div></div>
      {[["always","תמיד"],["ask","בזמן שימוש"],["never","ללא גישה"]].map(([v,l])=>(<div key={v} onClick={()=>S("locationPerm",v)} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"13px 0",borderBottom:"1px solid rgba(255,255,255,0.05)",cursor:"pointer",direction:"rtl"}}><span style={{color:settings.locationPerm===v?"#fff":"rgba(255,255,255,0.5)",fontSize:13,fontWeight:settings.locationPerm===v?600:400}}>{l}</span><div style={{width:18,height:18,borderRadius:"50%",border:`2px solid ${settings.locationPerm===v?"#00D68F":"rgba(255,255,255,0.2)"}`,background:settings.locationPerm===v?"#00D68F":"transparent",display:"flex",alignItems:"center",justifyContent:"center"}}>{settings.locationPerm===v&&<div style={{width:7,height:7,borderRadius:"50%",background:"#fff"}}/>}</div></div>))}
    </div>,
    camera:<div>
      <div style={{background:"rgba(59,139,255,0.06)",borderRadius:12,padding:"11px 13px",marginBottom:12,direction:"rtl",border:"1px solid rgba(59,139,255,0.12)"}}><div style={{color:"rgba(59,139,255,0.9)",fontWeight:600,fontSize:12,marginBottom:3}}>גישה למצלמה וגלריה</div><div style={{color:"rgba(255,255,255,0.4)",fontSize:11,lineHeight:1.6}}>נדרש לסיפורים, תמונות ופרסומים.</div></div>
      {[["always","אפשר תמיד"],["ask","שאל בכל פעם"],["never","אל תאפשר"]].map(([v,l])=>(<div key={v} onClick={()=>S("cameraAccess",v)} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"13px 0",borderBottom:"1px solid rgba(255,255,255,0.05)",cursor:"pointer",direction:"rtl"}}><span style={{color:settings.cameraAccess===v?"#fff":"rgba(255,255,255,0.5)",fontSize:13,fontWeight:settings.cameraAccess===v?600:400}}>{l}</span><div style={{width:18,height:18,borderRadius:"50%",border:`2px solid ${settings.cameraAccess===v?"#00D68F":"rgba(255,255,255,0.2)"}`,background:settings.cameraAccess===v?"#00D68F":"transparent",display:"flex",alignItems:"center",justifyContent:"center"}}>{settings.cameraAccess===v&&<div style={{width:7,height:7,borderRadius:"50%",background:"#fff"}}/>}</div></div>))}
    </div>,
    activity:<div>
      <Row label="מעקב פעילות אוטומטי" right={<Toggle val={settings.activityTracking} onChange={v=>S("activityTracking",v)}/>}/>
      <Row label="קצב לב" desc="דורש שעון חכם" right={<Toggle val={settings.heartRate} onChange={v=>S("heartRate",v)}/>}/>
      <Row label="הקלטה אוטומטית" right={<Toggle val={settings.autoRecord} onChange={v=>S("autoRecord",v)}/>}/>
      <Row label="ריצה / שחייה / אופניים" desc="ניקוד קהילתי בלבד  -  ללא ELO תחרותי" right={<span style={{background:"rgba(245,197,66,0.1)",color:"rgba(245,197,66,0.8)",fontSize:10,fontWeight:700,padding:"2px 7px",borderRadius:6}}>i</span>} border={false}/>
    </div>,
    appearance:<AppearanceSection settings={settings} S={S}/>,
    connected:<ConnectedAppsSection/>,
    smartwatch:<SmartWatchSection settings={settings} S={S}/>,
    legal:<LegalSection/>,
  };

  const menu=[{key:"account",label:"חשבון ופרופיל",desc:`@${user.username||"asaf_plays"}`},{key:"privacy",label:"פרטיות",desc:"מי רואה את הפרופיל"},{key:"notifications",label:"התראות",desc:"משחקים, הודעות ותזכורות"},{key:"location",label:"מיקום",desc:settings.locationPerm==="always"?"תמיד":settings.locationPerm==="ask"?"בזמן שימוש":"כבוי"},{key:"camera",label:"מצלמה וגלריה",desc:settings.cameraAccess==="always"?"תמיד":settings.cameraAccess==="ask"?"שאל":"כבוי"},{key:"activity",label:"פעילות ספורט",desc:"מעקב ו-ELO"},{key:"appearance",label:"מראה",desc:`${settings.language==="he"?"עברית":settings.language==="en"?"English":"عربي"} · ${settings.units}`},{key:"connected",label:"אפליקציות מחוברות",desc:"Strava, Apple Health ועוד"},{key:"smartwatch",label:"שעון חכם ובלוטות'",desc:settings.watchConnected?`✅ מחובר · ${settings.watchType||""}`:settings.btEnabled?"🔵 בלוטות' פעיל":"⚫ לא מחובר"},{key:"legal",label:"⚖️ Legal & Privacy",desc:"Terms · Privacy · GDPR · Cookies"}];

  if(section){
    const item=menu.find(m=>m.key===section);
    return(
      <div>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:20,direction:"rtl"}}>
          <button onClick={()=>setSection(null)} style={{width:34,height:34,borderRadius:10,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.08)",cursor:"pointer",color:"rgba(255,255,255,0.6)",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>←</button>
          <span style={{color:"#fff",fontWeight:700,fontSize:16}}>{item?.label}</span>
        </div>
        <div style={{background:"rgba(255,255,255,0.03)",borderRadius:16,border:"1px solid rgba(255,255,255,0.06)",overflow:"hidden"}}>
          {secContent[section]}
        </div>
      </div>
    );
  }

  return(
    <div>
      {/* User summary at top */}
      <div style={{display:"flex",alignItems:"center",gap:14,padding:"16px",background:"rgba(255,255,255,0.03)",borderRadius:18,border:"1px solid rgba(255,255,255,0.06)",marginBottom:20,direction:"rtl"}}>
        <div style={{width:52,height:52,borderRadius:"50%",background:"linear-gradient(135deg,#1a1f3a,#2d3561)",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:800,fontSize:18,border:"2px solid rgba(0,192,127,0.3)",overflow:"hidden",flexShrink:0}}>
          {user.photo?<img src={user.photo} style={{width:"100%",height:"100%",objectFit:"cover"}}/>:(user.initials||"AS")}
        </div>
        <div style={{flex:1}}>
          <div style={{color:"#fff",fontWeight:700,fontSize:15}}>{user.name}</div>
          <div style={{color:"rgba(255,255,255,0.4)",fontSize:12,marginTop:1}}>@{user.username||"asaf_plays"}</div>
        </div>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:2}}>
        {menu.map((m,i,arr)=>(
          <button key={m.key} onClick={()=>setSection(m.key)} style={{background:"rgba(255,255,255,0.03)",borderRadius:i===0?"14px 14px 4px 4px":i===arr.length-1?"4px 4px 14px 14px":"4px",padding:"14px 16px",border:"1px solid rgba(255,255,255,0.06)",direction:"rtl",display:"flex",alignItems:"center",gap:12,cursor:"pointer",width:"100%",marginBottom:1}}>
            <div style={{flex:1,textAlign:"right"}}>
              <div style={{color:"#fff",fontWeight:500,fontSize:13}}>{m.label}</div>
              {m.desc&&<div style={{color:"rgba(255,255,255,0.35)",fontSize:11,marginTop:1}}>{m.desc}</div>}
            </div>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="2"><polyline points="15 18 9 12 15 6"/></svg>
          </button>
        ))}
      </div>

      {/* ── ADD USER + LOGOUT ── */}
      <AddUserButton/>
      <LogoutButton/>
    </div>
  );
}

