/* ── Active Activity Overlay ──────────────────────────────────────── */
function ActiveActivityOverlay({mode, markers, onStop, onAddMarker, onOpenAR}){
  const [elapsed,setElapsed]=useState(0);
  const [dist,setDist]=useState(0);
  const [pace,setPace]=useState(0);
  const [alertMarker,setAlertMarker]=useState(null);
  const [dismissedAlerts,setDismissedAlerts]=useState(new Set());
  const [nearbyList,setNearbyList]=useState([]);

  // Simulate activity tracking
  useEffect(()=>{
    const t=setInterval(()=>{
      setElapsed(e=>e+1);
      setDist(d=>{
        const nd=d+(mode==="ride"?0.008:0.004);
        if(nd>0){
          setPace(elapsed>0?Math.max(3.5,6-nd*0.1):0);
        }
        return nd;
      });
    },1000);
    return()=>clearInterval(t);
  },[]);

  // Simulate proximity alerts
  useEffect(()=>{
    const t=setInterval(()=>{
      const available=markers.filter(m=>!dismissedAlerts.has(m.id));
      if(available.length>0&&Math.random()<0.3){
        const m=available[Math.floor(Math.random()*available.length)];
        setAlertMarker(m);
        // auto-dismiss after 4s
        setTimeout(()=>setAlertMarker(null),4000);
      }
      // update nearby list
      setNearbyList(markers.slice(0,4).map(m=>({
        ...m,
        dist:Math.floor(Math.random()*450+50)
      })));
    },3000);
    return()=>clearInterval(t);
  },[markers,dismissedAlerts]);

  function dismissAlert(){
    if(alertMarker){
      setDismissedAlerts(s=>new Set([...s,alertMarker.id]));
      setAlertMarker(null);
    }
  }

  const fmtTime=s=>{
    const m=Math.floor(s/60);
    const sec=s%60;
    return `${String(m).padStart(2,"0")}:${String(sec).padStart(2,"0")}`;
  };
  const fmtPace=p=>p>0?`${p.toFixed(1)}'/${mode==="ride"?"ק\"מ":"ק\"מ"}`:"--:--";

  const accentColor=mode==="ride"?"#CC44FF":mode==="run"?"#00FFB3":"#4D9FFF";

  return(
    <div style={{position:"fixed",inset:0,zIndex:850,display:"flex",flexDirection:"column",
      background:"rgba(1,2,8,0.96)",backdropFilter:"blur(24px)"}}>

      {/* Top bar */}
      <div style={{padding:"16px 20px 12px",display:"flex",alignItems:"center",
        justifyContent:"space-between",borderBottom:"1px solid rgba(255,255,255,0.06)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:10,height:10,borderRadius:"50%",background:accentColor,
            boxShadow:`0 0 10px ${accentColor}`,
            animation:"neonPulse 1.5s infinite"}}/>
          <span style={{color:"#fff",fontWeight:800,fontSize:15}}>
            {mode==="ride"?"🚴 רכיבה פעילה":mode==="run"?"🏃 ריצה פעילה":"▶️ פעילות פעילה"}
          </span>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={onOpenAR}
            style={{padding:"6px 12px",borderRadius:12,border:"1.5px solid rgba(204,68,255,0.4)",
              background:"rgba(204,68,255,0.12)",color:"#CC44FF",fontSize:11,
              fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",gap:5,alignItems:"center"}}>
            <span>🥽</span><span>AR</span>
          </button>
          <button onClick={onAddMarker}
            style={{padding:"6px 12px",borderRadius:12,border:`1.5px solid ${accentColor}50`,
              background:`${accentColor}12`,color:accentColor,fontSize:11,
              fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",gap:5,alignItems:"center"}}>
            <span>📍</span><span>סמן</span>
          </button>
        </div>
      </div>

      {/* Stats row */}
      <div style={{display:"flex",padding:"20px 20px 16px",gap:0,
        borderBottom:"1px solid rgba(255,255,255,0.04)"}}>
        {[
          {label:"זמן",value:fmtTime(elapsed),unit:""},
          {label:"מרחק",value:dist.toFixed(2),unit:"ק\"מ"},
          {label:mode==="ride"?"מהירות":"קצב",value:fmtPace(pace),unit:""},
        ].map((s,i)=>(
          <div key={i} style={{flex:1,textAlign:"center",
            borderRight:i<2?"1px solid rgba(255,255,255,0.06)":"none",
            padding:"0 8px"}}>
            <div style={{color:"rgba(255,255,255,0.35)",fontSize:9,fontWeight:600,
              letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:4}}>
              {s.label}
            </div>
            <div style={{color:accentColor,fontSize:22,fontWeight:900,
              fontVariantNumeric:"tabular-nums",lineHeight:1,
              filter:`drop-shadow(0 0 8px ${accentColor}60)`}}>
              {s.value}
            </div>
            {s.unit&&<div style={{color:"rgba(255,255,255,0.25)",fontSize:9,marginTop:2}}>
              {s.unit}
            </div>}
          </div>
        ))}
      </div>

      {/* Proximity alert */}
      {alertMarker&&(()=>{
        const mt=MARKER_TYPES.find(t=>t.k===alertMarker.type)||MARKER_TYPES[0];
        return(
          <div style={{margin:"12px 16px 0",padding:"12px 14px",borderRadius:16,
            background:`${mt.color}12`,border:`1.5px solid ${mt.color}50`,
            display:"flex",alignItems:"center",gap:10,
            animation:"slideDown 0.3s ease"}}>
            <div style={{width:42,height:42,borderRadius:12,flexShrink:0,
              background:`${mt.color}20`,display:"flex",alignItems:"center",
              justifyContent:"center",fontSize:22,
              boxShadow:`0 0 16px ${mt.color}40`}}>
              {alertMarker.icon}
            </div>
            <div style={{flex:1}}>
              <div style={{color:"#fff",fontWeight:800,fontSize:13,marginBottom:2}}>
                {alertMarker.label}
              </div>
              <div style={{color:mt.color,fontWeight:700,fontSize:11}}>
                בעוד ~{Math.floor(Math.random()*200+50)} מטר
              </div>
              <div style={{color:"rgba(255,255,255,0.35)",fontSize:10,marginTop:1}}>
                {alertMarker.note?.slice(0,36)}
              </div>
            </div>
            <button onClick={dismissAlert}
              style={{background:"none",border:"none",color:"rgba(255,255,255,0.3)",
                fontSize:16,cursor:"pointer",padding:"4px 6px"}}>
              ✕
            </button>
          </div>
        );
      })()}

      {/* Nearby markers list */}
      <div style={{flex:1,padding:"16px 16px 0",overflow:"hidden"}}>
        <div style={{color:"rgba(255,255,255,0.3)",fontSize:10,fontWeight:700,
          letterSpacing:"0.06em",marginBottom:10,textTransform:"uppercase"}}>
          סימונים על המסלול
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {nearbyList.map((m,i)=>{
            const mt=MARKER_TYPES.find(t=>t.k===m.type)||MARKER_TYPES[0];
            const urgency=m.dist<100?"#FF4757":m.dist<200?accentColor:"rgba(255,255,255,0.3)";
            return(
              <div key={m.id} style={{display:"flex",alignItems:"center",gap:10,
                padding:"10px 12px",borderRadius:14,
                background:"rgba(255,255,255,0.02)",
                border:"1px solid rgba(255,255,255,0.05)",
                animation:`fadeInUp 0.3s ease ${i*0.06}s both`}}>
                <span style={{fontSize:20,width:28,textAlign:"center"}}>{m.icon}</span>
                <div style={{flex:1}}>
                  <div style={{color:"rgba(255,255,255,0.75)",fontWeight:700,fontSize:12}}>
                    {m.label}
                  </div>
                  <div style={{color:"rgba(255,255,255,0.3)",fontSize:10,marginTop:1}}>
                    {m.note?.slice(0,32)}
                  </div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{color:urgency,fontWeight:900,fontSize:13,
                    filter:m.dist<100?`drop-shadow(0 0 6px ${urgency}80)`:"none"}}>
                    {m.dist}מ'
                  </div>
                  {m.dist<100&&<div style={{color:"#FF4757",fontSize:8,fontWeight:700,
                    letterSpacing:"0.05em"}}>NEAR</div>}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Stop button */}
      <div style={{padding:"20px 20px 32px"}}>
        <button onClick={onStop}
          style={{width:"100%",padding:"16px",borderRadius:18,border:"none",
            cursor:"pointer",fontFamily:"inherit",fontWeight:900,fontSize:15,
            background:"linear-gradient(135deg,#FF4757,#CC1133)",
            color:"#fff",boxShadow:"0 6px 24px rgba(255,71,87,0.4)",
            display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
          <span style={{fontSize:18}}>⏹</span>
          <span>עצור פעילות</span>
        </button>
      </div>
    </div>
  );
}

