/* ── MapLoadingState ─────────────────────────────────────────────────── */
function MapLoadingState(){
  const [dots,setDots]=useState(0);
  useEffect(()=>{
    const t=setInterval(()=>setDots(d=>(d+1)%4),400);
    return()=>clearInterval(t);
  },[]);
  return(
    <div style={{
      position:"absolute",inset:0,
      background:"linear-gradient(160deg,#070A14,#0a1225)",
      display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",
      zIndex:15,
    }}>
      {/* Pulsing map icon */}
      <div style={{position:"relative",marginBottom:24}}>
        <div style={{
          width:64,height:64,borderRadius:18,
          background:"rgba(0,255,179,0.08)",
          border:"1.5px solid rgba(0,255,179,0.25)",
          display:"flex",alignItems:"center",justifyContent:"center",
          fontSize:28,
          boxShadow:"0 0 32px rgba(0,255,179,0.15)",
          animation:"neonPulse 2s infinite",
        }}>🗺️</div>
        {/* Rotating ring */}
        <div style={{
          position:"absolute",top:-6,left:-6,right:-6,bottom:-6,
          borderRadius:24,
          border:"1.5px solid transparent",
          borderTopColor:"#00FFB3",
          borderRightColor:"#00FFB3",
          animation:"spin 1.2s linear infinite",
        }}/>
      </div>
      <div style={{color:"#FFFDE8",fontWeight:700,fontSize:14,marginBottom:6}}>
        טוען Google Maps{"·".repeat(dots+1)}
      </div>
      <div style={{color:"rgba(255,255,255,0.3)",fontSize:11}}>
        Amsterdam · Heatmap Layer
      </div>
    </div>
  );
}

