/* ── HeatmapLegend ────────────────────────────────────────────────────── */
function HeatmapLegend({visible}){
  if(!visible) return null;
  return(
    <div style={{
      position:"absolute",top:60,right:12,zIndex:10,
      background:"rgba(7,10,20,0.88)",backdropFilter:"blur(14px)",
      border:"1px solid rgba(255,255,255,0.09)",
      borderRadius:14,padding:"10px 12px",minWidth:90,
    }}>
      <div style={{color:"rgba(255,255,255,0.35)",fontSize:8,
        fontWeight:700,marginBottom:8,letterSpacing:"0.07em",textAlign:"center",direction:"rtl"}}>
        עוצמת פעילות
      </div>

      {/* Gradient bar */}
      <div style={{
        width:"100%",height:8,borderRadius:4,marginBottom:8,
        background:"linear-gradient(90deg,rgba(0,80,255,0.7),rgba(0,220,130,0.85),rgba(200,255,0,0.9),rgba(255,100,0,1),rgba(255,0,0,1))",
        boxShadow:"0 0 8px rgba(255,50,50,0.25)",
      }}/>

      {/* Labels */}
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
        {["נמוכה","גבוהה"].map(l=>(
          <span key={l} style={{color:"rgba(255,255,255,0.3)",fontSize:8,fontWeight:600}}>{l}</span>
        ))}
      </div>

      {/* Colour dots */}
      {[
        {c:"#4D9FFF",l:"נמוכה"},
        {c:"#00C07F",l:"בינונית"},
        {c:"#FFD166",l:"גבוהה"},
        {c:"#FF4757",l:"חמה מאוד"},
      ].map(({c,l})=>(
        <div key={l} style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}>
          <div style={{width:8,height:8,borderRadius:"50%",background:c,flexShrink:0,
            boxShadow:`0 0 5px ${c}88`}}/>
          <span style={{color:"rgba(255,255,255,0.45)",fontSize:9}}>{l}</span>
        </div>
      ))}
    </div>
  );
}

/* ── Google Maps Heatmap Layer ────────────────────────────────────────── */
function GoogleHeatmapLayer({map, visible, activityFilter}){
  const heatRef = useRef(null);

  // Memoize filtered point array so it only recomputes when filter changes
  const filteredPts = useMemo(()=>(
    activityFilter==="all"
      ? AMS_HEATMAP_ACTIVITY
      : AMS_HEATMAP_ACTIVITY.filter(p=>p.type===activityFilter)
  ),[activityFilter]);

  useEffect(()=>{
    if(!map||!window.google?.maps?.visualization) return;
    if(heatRef.current){ heatRef.current.setMap(null); heatRef.current=null; }
    if(!visible) return;

    const data = filteredPts.map(p=>({
      location: new window.google.maps.LatLng(p.lat, p.lng),
      weight:   p.weight,
    }));

    heatRef.current = new window.google.maps.visualization.HeatmapLayer({
      data,
      map,
      radius:       40,
      opacity:      0.84,
      gradient:     GMAPS_HEAT_GRADIENT,
      maxIntensity: 10,
      dissipating:  true,
    });

    return()=>{ if(heatRef.current){ heatRef.current.setMap(null); heatRef.current=null; } };
  },[map,visible,filteredPts]);

  return null;
}

/* ── Live activity pulse dots — Google Maps OverlayView ──────────── */
function LiveActivityDots({map, visible}){
  const dotsRef = useRef([]);
  const [liveDots] = useState(()=>{
    // Simulate ~22 users active in Amsterdam right now
    const spots=[
      [52.3578,4.8705],[52.3802,4.9000],[52.3676,4.9041],
      [52.3318,4.8993],[52.3867,4.8720],[52.3608,4.9185],
      [52.3585,4.8840],[52.3705,4.8490],[52.3740,4.8900],
      [52.3861,4.8290],[52.3470,4.8673],[52.3614,4.9203],
    ];
    return Array.from({length:22},(_,i)=>({
      id:i,
      lat: spots[i%spots.length][0]+(Math.random()-0.5)*0.005,
      lng: spots[i%spots.length][1]+(Math.random()-0.5)*0.006,
      type: ["run","ride","walk","football","basketball"][i%5],
    }));
  });

  useEffect(()=>{
    if(!map||!window.google?.maps){
      dotsRef.current.forEach(o=>o.setMap?.(null));
      dotsRef.current=[];
      return;
    }
    if(!visible){
      dotsRef.current.forEach(o=>o.setMap?.(null));
      return;
    }

    dotsRef.current.forEach(o=>o.setMap?.(null));
    dotsRef.current=[];

    const google=window.google;

    liveDots.forEach(d=>{
      const color=d.type==="run"?"#00FFB3":d.type==="ride"?"#CC44FF":
                  d.type==="football"?"#00C07F":d.type==="basketball"?"#FF9A3C":"#4D9FFF";

      const div=document.createElement("div");
      div.style.cssText=`
        width:10px;height:10px;border-radius:50%;
        background:${color};
        box-shadow:0 0 8px ${color},0 0 16px ${color}44;
        position:absolute;transform:translate(-50%,-50%);
        pointer-events:none;`;

      const overlay=new google.maps.OverlayView();
      overlay.onAdd=function(){ this.getPanes().overlayLayer.appendChild(div); };
      overlay.draw=function(){
        const pt=this.getProjection().fromLatLngToDivPixel(new google.maps.LatLng(d.lat,d.lng));
        if(pt){ div.style.left=pt.x+"px"; div.style.top=pt.y+"px"; }
      };
      overlay.onRemove=function(){ if(div.parentNode) div.parentNode.removeChild(div); };
      overlay.setMap(map);
      dotsRef.current.push(overlay);
    });

    return()=>{ dotsRef.current.forEach(o=>o.setMap?.(null)); dotsRef.current=[]; };
  },[map,visible,liveDots]);

  return null;
}

