/* ── AR Overlay mode ──────────────────────────────────────────────── */
function ARModeOverlay({markers,onClose}){
  const [heading,setHeading]=useState(0);
  const [mockDist,setMockDist]=useState({});
  const videoRef=useRef(null);

  useEffect(()=>{
    // Simulate device orientation
    const t=setInterval(()=>{
      setHeading(h=>(h+1)%360);
      const d={};
      markers.slice(0,3).forEach(m=>{ d[m.id]=Math.floor(Math.random()*400+50); });
      setMockDist(d);
    },400);

    // Try camera
    if(navigator.mediaDevices?.getUserMedia){
      navigator.mediaDevices.getUserMedia({video:{facingMode:"environment"}})
        .then(s=>{
          if(videoRef.current){videoRef.current.srcObject=s;videoRef.current.play();}
        }).catch(()=>{});
    }
    return()=>{
      clearInterval(t);
      if(videoRef.current?.srcObject){
        videoRef.current.srcObject.getTracks().forEach(t=>t.stop());
      }
    };
  },[]);

  // Show 3 nearest markers as AR overlays
  const arMarkers=markers.slice(0,3);

  return(
    <div style={{position:"fixed",inset:0,zIndex:900,background:"#000",
      overflow:"hidden"}}>

      {/* camera feed / dark bg */}
      <video ref={videoRef} playsInline muted
        style={{position:"absolute",inset:0,width:"100%",height:"100%",
          objectFit:"cover",opacity:0.6}}/>

      {/* dark overlay */}
      <div style={{position:"absolute",inset:0,
        background:"linear-gradient(180deg,rgba(0,0,0,0.3)0%,rgba(0,0,0,0.1)50%,rgba(0,0,0,0.5)100%)"}}/>

      {/* AR marker cards — floating */}
      {arMarkers.map((m,i)=>{
        const dist=mockDist[m.id]||150;
        const positions=[[20,30],[38,55],[62,45]]; // % positions
        const [left,top]=positions[i];
        const mt=MARKER_TYPES.find(t=>t.k===m.type)||MARKER_TYPES[0];
        return(
          <div key={m.id} style={{
            position:"absolute",
            left:`${left}%`,top:`${top}%`,
            transform:"translate(-50%,-50%)",
            display:"flex",flexDirection:"column",
            alignItems:"center",gap:6,
            animation:`fadeInUp 0.4s ease ${i*0.15}s both`}}>

            {/* floating icon */}
            <div style={{
              width:56,height:56,borderRadius:"50%",
              background:`${mt.color}20`,
              border:`2px solid ${mt.color}80`,
              backdropFilter:"blur(12px)",
              display:"flex",alignItems:"center",justifyContent:"center",
              fontSize:26,
              boxShadow:`0 0 20px ${mt.color}50`,
              animation:"neonPulse 2s infinite"}}>
              {m.icon}
            </div>

            {/* info card */}
            <div style={{
              background:"rgba(1,2,8,0.82)",
              backdropFilter:"blur(16px)",
              border:`1px solid ${mt.color}40`,
              borderRadius:12,padding:"6px 12px",
              textAlign:"center",
              boxShadow:`0 4px 20px rgba(0,0,0,0.5)`}}>
              <div style={{color:"#fff",fontWeight:700,fontSize:11,marginBottom:2}}>
                {m.label}
              </div>
              <div style={{color:mt.color,fontWeight:900,fontSize:13}}>
                {dist} מ'
              </div>
              <div style={{color:"rgba(255,255,255,0.4)",fontSize:9,marginTop:1}}>
                {m.note?.slice(0,24)}...
              </div>
            </div>

            {/* connector line */}
            <div style={{width:1,height:dist>200?30:20,
              background:`linear-gradient(${mt.color},transparent)`,
              opacity:0.5}}/>
          </div>
        );
      })}

      {/* compass heading indicator */}
      <div style={{position:"absolute",top:20,left:"50%",
        transform:"translateX(-50%)",
        background:"rgba(1,2,8,0.7)",backdropFilter:"blur(12px)",
        border:"1px solid rgba(0,255,179,0.2)",
        borderRadius:20,padding:"6px 16px",
        display:"flex",alignItems:"center",gap:8}}>
        <div style={{fontSize:14,
          transform:`rotate(${heading}deg)`,
          transition:"transform 0.4s",display:"inline-block"}}>
          🧭
        </div>
        <span style={{color:"#00FFB3",fontWeight:700,fontSize:11}}>
          AR — מסלול פעיל
        </span>
        <span style={{color:"rgba(255,255,255,0.4)",fontSize:10}}>
          {heading}°
        </span>
      </div>

      {/* nearby markers list (bottom strip) */}
      <div style={{position:"absolute",bottom:80,left:0,right:0,
        overflowX:"auto",padding:"0 16px"}}>
        <div style={{display:"flex",gap:8,width:"max-content"}}>
          {markers.slice(0,5).map((m,i)=>{
            const mt=MARKER_TYPES.find(t=>t.k===m.type)||MARKER_TYPES[0];
            const d=mockDist[m.id]||(80+i*60);
            return(
              <div key={m.id} style={{
                background:"rgba(1,2,8,0.85)",
                backdropFilter:"blur(16px)",
                border:`1px solid ${mt.color}35`,
                borderRadius:14,padding:"10px 12px",
                display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
                <span style={{fontSize:20}}>{m.icon}</span>
                <div>
                  <div style={{color:"#fff",fontWeight:700,fontSize:11}}>
                    {m.label}
                  </div>
                  <div style={{color:mt.color,fontWeight:800,fontSize:12}}>
                    {d} מ'
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* close button */}
      <button onClick={onClose}
        style={{position:"absolute",top:20,right:16,
          width:40,height:40,borderRadius:"50%",border:"none",
          background:"rgba(1,2,8,0.8)",backdropFilter:"blur(12px)",
          color:"#fff",fontSize:18,cursor:"pointer",
          display:"flex",alignItems:"center",justifyContent:"center",
          border:"1px solid rgba(255,255,255,0.15)"}}>
        ✕
      </button>

      {/* AR label */}
      <div style={{position:"absolute",bottom:20,left:"50%",
        transform:"translateX(-50%)",
        color:"rgba(255,255,255,0.3)",fontSize:9,
        fontWeight:700,letterSpacing:"0.15em",textTransform:"uppercase"}}>
        AR MODE — MATCHD SPORT DISCOVERY
      </div>
    </div>
  );
}

/* ── Add Marker Sheet ─────────────────────────────────────────────── */
function AddMarkerSheet({onClose,onAdd}){
  const C=useC();
  const [selectedType,setSelectedType]=useState(null);
  const [note,setNote]=useState("");

  function handleAdd(){
    if(!selectedType)return;
    const mt=MARKER_TYPES.find(t=>t.k===selectedType);
    onAdd({
      id:Date.now(),
      lat:32.0848+(Math.random()-0.5)*0.02,
      lng:34.7748+(Math.random()-0.5)*0.02,
      type:selectedType,
      icon:mt.icon,
      label:mt.label,
      author:"אתה",
      ago:"עכשיו",
      confirms:0,
      reports:0,
      note:note||"סימון חדש",
    });
    onClose();
  }

  return(
    <div style={{padding:"8px 16px 24px",direction:"rtl"}}>
      <div style={{color:"rgba(255,255,255,0.4)",fontSize:12,
        marginBottom:14,textAlign:"center"}}>
        בחר סוג סימון
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>
        {MARKER_TYPES.map(mt=>{
          const on=selectedType===mt.k;
          return(
            <button key={mt.k} onClick={()=>setSelectedType(mt.k)}
              style={{
                padding:"12px 10px",borderRadius:14,cursor:"pointer",
                fontFamily:"inherit",textAlign:"right",
                border:`1.5px solid ${on?mt.color:mt.color+"25"}`,
                background:on?`${mt.color}12`:`${mt.color}05`,
                display:"flex",alignItems:"center",gap:8}}>
              <span style={{fontSize:20,flexShrink:0}}>{mt.icon}</span>
              <span style={{color:on?mt.color:"rgba(255,255,255,0.6)",
                fontWeight:on?700:400,fontSize:12}}>
                {mt.label}
              </span>
            </button>
          );
        })}
      </div>

      {/* note input */}
      <div style={{marginBottom:16}}>
        <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginBottom:6}}>
          הערה (אופציונלי)
        </div>
        <textarea
          value={note}
          onChange={e=>setNote(e.target.value)}
          placeholder="תיאור קצר של הסימון..."
          style={{
            width:"100%",padding:"10px 12px",borderRadius:12,
            background:"rgba(255,255,255,0.04)",
            border:"1px solid rgba(255,255,255,0.1)",
            color:"#fff",fontSize:13,fontFamily:"inherit",
            resize:"none",height:72,outline:"none",
            boxSizing:"border-box"}}/>
      </div>

      <button onClick={handleAdd} disabled={!selectedType}
        style={{
          width:"100%",padding:"14px",borderRadius:14,border:"none",
          cursor:selectedType?"pointer":"not-allowed",fontFamily:"inherit",
          fontWeight:800,fontSize:14,
          background:selectedType
            ?"linear-gradient(135deg,#00FFB3,#00C07F)"
            :"rgba(255,255,255,0.06)",
          color:selectedType?"#000":"rgba(255,255,255,0.3)",
          transition:"all 0.2s"}}>
        📍 הוסף סימון
      </button>
    </div>
  );
}

/* ── Marker Popup ─────────────────────────────────────────────────── */
